-- ----------------------------
-- Procedure structure for ActualizaPassword
-- ----------------------------
DROP PROCEDURE IF EXISTS `ActualizaPassword`;
delimiter ;;
CREATE PROCEDURE `ActualizaPassword`(IN P_User_Cve VARCHAR(10), IN P_Password VARCHAR(100))
BEGIN

UPDATE tuser
SET tuser_pass=AES_ENCRYPT(P_Password,tuser_clave)
WHERE UPPER(tuser_clave)=UPPER(P_User_Cve);
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for Actualiza_Estatus_Comentario
-- ----------------------------
DROP PROCEDURE IF EXISTS `Actualiza_Estatus_Comentario`;
delimiter ;;
CREATE PROCEDURE `Actualiza_Estatus_Comentario`(IN IDDocumento_in INT,    
IN Comentario_in varchar(1000),
IN IDEstatusDoc_in int,
IN User_in varchar (100))
BEGIN
DECLARE IDUsuario_in int;
SET IDUsuario_in = (SELECT IDUsuario FROM Usuario WHERE Login=User_in);
IF Comentario_in='' THEN
UPDATE Documentos_Alumno SET IDEstatusDocumento=IDEstatusDoc_in,FechaUltModif=current_timestamp() WHERE IDDocumento=IDDocumento_in;
ELSE 
UPDATE Documentos_Alumno SET IDEstatusDocumento=IDEstatusDoc_in,FechaUltModif=current_timestamp() WHERE IDDocumento=IDDocumento_in;
END IF;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for Actualiza_Estatus_Expediente
-- ----------------------------
DROP PROCEDURE IF EXISTS `Actualiza_Estatus_Expediente`;
delimiter ;;
CREATE PROCEDURE `Actualiza_Estatus_Expediente`(IDEstatusDoc_in int,
IDAlumno_in varchar(10))
BEGIN
DECLARE No_total_doc int;
DECLARE No_Entregados int;
DECLARE No_Aceptado int;

SET No_total_doc=
(SELECT DISTINCT COUNT(*)     
FROM TiposDocumento_nivel TDA              
JOIN TipoDocumento TD ON TD.IDTipoDocumento = TDA.IDTipoDocumento                   
JOIN Alumno AL ON  AL.CodigoProcedencia = TDA.IDProcedencia AND AL.CodigoTipoIngreso = TDA.IDTipoIngreso AND AL.IDNivel=TDA.IDNivel  AND AL.IDModalidad=TDA.IDModalidad AND AL.IDAlumno =IDAlumno_in);
SET No_Entregados=(SELECT DISTINCT COUNT(*) FROM Documentos_Alumno WHERE IDAlumno=IDAlumno_in AND IDEstatusDocumento='3');
SET No_Aceptado=(SELECT DISTINCT COUNT(*)No_Aceptado FROM Documentos_Alumno WHERE IDAlumno=IDAlumno_in AND IDEstatusDocumento='1');

IF IDEstatusDoc_in IN (2,5)
THEN
UPDATE Alumno SET IDEstatusExpediente=13 WHERE IDAlumno=IDAlumno_in;
ELSEIF IDEstatusDoc_in=3 AND No_total_doc=No_Entregados
THEN
UPDATE Alumno SET IDEstatusExpediente=14 WHERE IDAlumno=IDAlumno_in;
ELSEIF IDEstatusDoc_in=1 AND No_total_doc=No_Aceptado
THEN 
UPDATE Alumno SET IDEstatusExpediente=11 WHERE IDAlumno=IDAlumno_in;
END IF;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for Actualiza_Menu
