delimiter ;;
CREATE PROCEDURE `Actualiza_Menu_Opciones`(IN P_Menu INT, IN P_Opcion int, IN P_Descripcion VARCHAR(80), IN P_Estatus VARCHAR(1), P_Relacion VARCHAR(20), P_Forma VARCHAR(5))
BEGIN
	UPDATE tmede
    SET tmede_desc=P_Descripcion,
    tmede_estatus=P_Estatus,
    tmede_rel=P_Relacion,
    tmede_forma=P_Forma
    WHERE tmede_tmenu_clave=P_Menu AND
	tmede_clave=P_Opcion;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for Actualiza_Password
-- ----------------------------
DROP PROCEDURE IF EXISTS `Actualiza_Password`;
delimiter ;;
CREATE PROCEDURE `Actualiza_Password`(IN P_CVE VARCHAR(10), IN P_USER_PASS VARCHAR(100))
BEGIN
DECLARE vmPass VARCHAR(100);
	SELECT cast(AES_ENCRYPT(tuser_pass,tuser_clave) as char) pass 
    INTO vmPass
    FROM tuser
    WHERE tuser_clave=P_CVE;
    
	UPDATE tuser
    SET tuser_pass=vmPass
    WHERE tuser_clave=P_CVE;
END
;;
delimiter ;

