-- ----------------------------
-- Function structure for calcularBeneficio
-- ----------------------------
DROP FUNCTION IF EXISTS `calcularBeneficio`;
delimiter ;;
CREATE FUNCTION `calcularBeneficio`(coste FLOAT, precio FLOAT)
 RETURNS decimal(9,2)
  READS SQL DATA 
BEGIN
    DECLARE beneficio DECIMAL(9,2);
    SET beneficio = precio - coste;
    RETURN beneficio;
END
;;
delimiter ;

-- ----------------------------
-- Function structure for comentarios_documento
-- ----------------------------
DROP FUNCTION IF EXISTS `comentarios_documento`;
delimiter ;;
CREATE FUNCTION `comentarios_documento`(IDDocumento_in int)
 RETURNS longtext CHARSET utf8mb4
  DETERMINISTIC
BEGIN
DECLARE Usuario VARCHAR(25);
DECLARE FechaModif DATETIME;
DECLARE Comentario VARCHAR(250);
DECLARE Regreso LONGTEXT;
DECLARE salida BOOLEAN;
DECLARE done INT DEFAULT 0; 
DECLARE comentario_cursor CURSOR FOR 
    SELECT U.Nombre, c.FechaUltModif, Comentario
    FROM Comentarios C
    INNER JOIN Usuario U ON C.idUsuario = U.IDUsuario
    WHERE IDDocumento = IDDocumento_in;
  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;
    SET Regreso = '';    
  
    OPEN comentario_cursor;
    my_cur_loop:
    LOOP FETCH comentario_cursor INTO Usuario, FechaModif, Comentario;
        IF done = 1 THEN
            LEAVE my_cur_loop;
        END IF;
        SET Regreso=CONCAT(Regreso,DATE_FORMAT(FechaModif, "%d/%m/%Y"),'-',Usuario, '-' , Comentario , '|');
    END LOOP my_cur_loop;
CLOSE comentario_cursor;

RETURN Regreso;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for Eliminar_Permisos_Campus
-- ----------------------------
DROP PROCEDURE IF EXISTS `Eliminar_Permisos_Campus`;
delimiter ;;
CREATE PROCEDURE `Eliminar_Permisos_Campus`(IN IDCampus_in VARCHAR(5),      
IN IDUsuario_in int,  
IN IDRol_in int,
IN UserLog varchar(50))
BEGIN
Declare Nombre_usuario varchar(250);
Declare Campus_usuario varchar (250);
Declare Descripcion_in varchar (500);
SET Nombre_usuario= (SELECT DISTINCT Nombre as Nombre_u FROM Usuario WHERE IDUsuario=IDUsuario_in);
SET Campus_usuario= (SELECT DISTINCT tcamp_desc as Nombre_c FROM tcamp WHERE tcamp_clave=IDCampus_in);
SET Descripcion_in=(SELECT CONCAT('Se a eliminado el usuario ',Nombre_usuario, ' del campus ',Campus_usuario));

IF EXISTS (SELECT * FROM Permisos_Campus WHERE IDUsuario=IDUsuario_in AND IDRol=IDRol_in AND IDCampus=IDCampus_in) THEN
DELETE FROM Permisos_Campus WHERE IDCampus=IDCampus_in AND IDRol=IDRol_in AND IDUsuario=IDUsuario_in;
END IF;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for Eliminar_Permisos_Documentos
-- ----------------------------
DROP PROCEDURE IF EXISTS `Eliminar_Permisos_Documentos`;
delimiter ;;
CREATE PROCEDURE `Eliminar_Permisos_Documentos`(IN IDTipoDocumento_in int,     
IN IDUsuario_in int,  
IN IDRol_in int,
IN UserLog varchar(50))
BEGIN
Declare Nombre_in varchar(250);
Declare id_saes_in varchar (30);

SET Nombre_in= (SELECT Nombre as Nombre_u FROM Usuario WHERE IDUsuario=IDUsuario_in);
SET id_saes_in = (SELECT id_saes FROM TipoDocumento WHERE IDTipoDocumento=IDTipoDocumento_in);

IF EXISTS (SELECT * FROM Permisos_Documentos WHERE IDUsuario=IDUsuario_in AND IDRol=IDRol_in AND IDTipoDocumento=IDTipoDocumento_in)
THEN 
DELETE FROM Permisos_Documentos WHERE IDTipoDocumento=IDTipoDocumento_in AND IDRol=IDRol_in AND IDUsuario=IDUsuario_in;
END IF;

END
;;
delimiter ;

