-- ----------------------------
-- Function structure for estatus_expediente
-- ----------------------------
DROP FUNCTION IF EXISTS `estatus_expediente`;
delimiter ;;
CREATE FUNCTION `estatus_expediente`(iden varchar(10))
 RETURNS varchar(12) CHARSET utf8mb4
  READS SQL DATA 
BEGIN
declare expediente varchar(12); 
declare doctos int;
declare aceptados int;

select count(*) into doctos  from tpers 
inner join tadmi a on tadmi_tpers_num = tpers_num  
inner join tredo on tredo_tpers_num = tadmi_tpers_num and tredo_tpees_clave = tadmi_tpees_clave    
   and tredo_consecutivo = tadmi_consecutivo and tredo_estatus = 'A'  
inner join tdocu on tredo_tdocu_clave = tdocu_clave and tdocu_estatus = 'A'  
inner join TipoDocumento x on id_saes = tdocu_clave  
LEFT JOIN Documentos_Alumno b ON IDAlumno = tpers_id and x.IDTipoDocumento = b.IDTipoDocumento  
where tpers_id = iden;

select count(*) into aceptados  from tpers 
inner join tadmi a on tadmi_tpers_num = tpers_num  
inner join tredo on tredo_tpers_num = tadmi_tpers_num and tredo_tpees_clave = tadmi_tpees_clave    
   and tredo_consecutivo = tadmi_consecutivo and tredo_estatus = 'A'  
inner join tdocu on tredo_tdocu_clave = tdocu_clave and tdocu_estatus = 'A'  
inner join TipoDocumento x on id_saes = tdocu_clave  
LEFT JOIN Documentos_Alumno b ON IDAlumno = tpers_id and x.IDTipoDocumento = b.IDTipoDocumento  
where tpers_id = iden and  IDEstatusDocumento=1;

if aceptados = 0 or doctos = 0 then 
    SET expediente='PENDIENTE';
end if;
if aceptados = doctos and doctos > 0 then 
    SET expediente='COMPLETO';
end if;
if aceptados > 0 and aceptados < doctos then 
    SET expediente='INCOMPLETO';
end if;


RETURN expediente;
END
;;
delimiter ;

-- ----------------------------
-- Function structure for fecha
-- ----------------------------
DROP FUNCTION IF EXISTS `fecha`;
delimiter ;;
CREATE FUNCTION `fecha`(f_conv varchar(10))
 RETURNS varchar(30) CHARSET utf8mb4
  READS SQL DATA 
BEGIN
declare f varchar(50);

select distinct concat( lpad(day(f_conv), 2,'0') ,' ',
case when month(f_conv)=1 then  'Enero'
     when month(f_conv)=2 then  'Febrero'
     when month(f_conv)=3 then  'Marzo'
     when month(f_conv)=4 then  'Abril'
     when month(f_conv)=5 then  'Mayo'
     when month(f_conv)=6 then  'Junio'
     when month(f_conv)=7 then  'Julio'
     when month(f_conv)=8 then  'Agosto'
     when month(f_conv)=9 then  'Septiembre'
     when month(f_conv)=10 then  'Octubre'
     when month(f_conv)=11 then  'Noviembre'
     when month(f_conv)=12 then  'Diciembre'
end,' ',
year(f_conv)) into f;

RETURN f;
END
;;
delimiter ;

