-- ----------------------------
-- Procedure structure for Login
-- ----------------------------
DROP PROCEDURE IF EXISTS `Login`;
delimiter ;;
CREATE PROCEDURE `Login`(IN username varchar(100), IN password_text varchar(100),OUT Result boolean)
BEGIN
Declare Password_correct varchar(100);
SET Password_correct=(SELECT DISTINCT CAST(AES_DECRYPT(tuser_pass,username)AS CHAR(12)) FROM tuser where tuser_clave=username);
IF Password_correct=password_text THEN
SET Result=true;
ELSE
SET Result=false;
END IF;
END
;;
delimiter ;

