BEGIN
	select b.tmede_clave, b.tmede_desc,
    case when a.tusme_update=1 then 'true' else 'false' end tusme_update, 
	case when a.tusme_select=1 then 'true' else 'false' end tusme_select,
    b.tmede_tmenu_clave
	from tusme a, tmede b
	where a.tusme_trole_clave=P_Rol
	and   b.tmede_clave=a.tusme_tmede_clave
	and b.tmede_tmenu_clave=P_Menu
	and   b.tmede_tmenu_clave=a.tusme_tmenu_clave;
    
END
