delimiter ;;
CREATE PROCEDURE `Obtener_Comentarios_Documento`(IN IDDocumento_in int)
BEGIN
SELECT B.Nombre,A.Comentario,C.Nombre Estatus,DATE_FORMAT(A.FechaUltModif,"%m-%d-%Y %h:%i:%s %p")FechaUltModif
FROM Comentarios A
INNER JOIN Usuario B ON A.IDUsuario = B.IDUsuario
INNER JOIN Estatus C ON A.IDEstatusDocumento=C.IDEstatus
WHERE A.IDDocumento=IDDocumento_in
AND A.Comentario<>'Cambio de Estatus'
ORDER BY A.IDComentario DESC;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for Obtener_Listado_Alumnos
-- ----------------------------
DROP PROCEDURE IF EXISTS `Obtener_Listado_Alumnos`;
delimiter ;;
CREATE PROCEDURE `Obtener_Listado_Alumnos`(IN Rol VARCHAR(30),            
IN Status VARCHAR(10),
IN User VARCHAR (100))
BEGIN
DECLARE IDUsuario_in Int;
DECLARE IDRol_in Int ;
SET IDUsuario_in = (SELECT DISTINCT  IDUsuario FROM Usuario WHERE Login=User);
SET IDRol_in = (SELECT DISTINCT IDRol FROM Rol WHERE Nombre=Rol);

IF Status='COMPLETO' THEN
 SELECT A.IDAlumno,A.Nombre,C.tcamp_desc Campus,N.tnive_desc Nivel, tprog_desc Programa,(select estatus_expediente(A.IDAlumno)) Estatus_Alumno,  fecha(date_format(A.FechaRegistro,'%Y-%m-%d')) FechaRegistro,
 fecha(date_format(A.FechaUltNotificacion,'%Y-%m-%d')) FechaUltNotificacion,A.NoAlerta,M.tmoda_desc Modalidad
 FROM Alumno A
 INNER JOIN Estatus EA ON A.IDEstatusAlumno=EA.IDEstatus
 INNER JOIN tcamp C ON A.IDCampus=C.tcamp_clave
 INNER JOIN tmoda M ON A.IDModalidad=M.tmoda_clave
 INNER JOIN tnive N ON A.IDNivel=N.tnive_clave
 INNER JOIN tprog ON A.IDPrograma=tprog_clave
INNER JOIN (SELECT DISTINCT Z.IDUsuario,Z.IDRol,Y.IDCampus,X.IDNivel
 FROM Roles_Usuarios Z
 INNER JOIN Permisos_Campus Y ON Z.IDRol=Y.IDRol AND Z.IDUsuario=Y.IDUsuario
 INNER JOIN Permisos_Nivel X ON Z.IDRol=X.IDRol AND Z.IDUsuario=X.IDUsuario  
 ) Permisos ON A.IDCampus=Permisos.IDCampus AND A.IDNivel=Permisos.IDNivel
 WHERE EE.Nombre = Status
 AND Permisos.IDUsuario= IDUsuario_in
 AND Permisos.IDRol=IDRol_in;
ELSE
  SELECT A.IDAlumno,A.Nombre,C.tcamp_desc Campus,N.tnive_desc Nivel, tprog_desc Programa,(select estatus_expediente(A.IDAlumno)) Estatus_Alumno,  fecha(date_format(A.FechaRegistro,'%Y-%m-%d')) FechaRegistro,
 fecha(date_format(A.FechaUltNotificacion,'%Y-%m-%d')) FechaUltNotificacion,A.NoAlerta,M.tmoda_desc Modalidad
 FROM Alumno A
 INNER JOIN Estatus EA ON A.IDEstatusAlumno=EA.IDEstatus
 INNER JOIN tcamp C ON A.IDCampus=C.tcamp_clave
 INNER JOIN tmoda M ON A.IDModalidad=M.tmoda_clave
 INNER JOIN tnive N ON A.IDNivel=N.tnive_clave
 INNER JOIN tprog ON A.IDPrograma=tprog_clave
INNER JOIN (SELECT DISTINCT Z.IDUsuario,Z.IDRol,Y.IDCampus,X.IDNivel
 FROM Roles_Usuarios Z
 INNER JOIN Permisos_Campus Y ON Z.IDRol=Y.IDRol AND Z.IDUsuario=Y.IDUsuario
 INNER JOIN Permisos_Nivel X ON Z.IDRol=X.IDRol AND Z.IDUsuario=X.IDUsuario  
 ) Permisos ON A.IDCampus=Permisos.IDCampus AND A.IDNivel=Permisos.IDNivel
 WHERE Permisos.IDUsuario= IDUsuario_in
 AND Permisos.IDRol=IDRol_in;
END IF;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for Obtener_Listado_Documentos_Alumno
-- ----------------------------
DROP PROCEDURE IF EXISTS `Obtener_Listado_Documentos_Alumno`;
delimiter ;;
CREATE PROCEDURE `Obtener_Listado_Documentos_Alumno`(IN IDAlumno_in VARCHAR(10),
IN Rol VARCHAR(30))
BEGIN
DECLARE IDRol_in Int; 
SET IDRol_in = (SELECT DISTINCT IDRol FROM Rol WHERE Nombre=Rol);

select distinct  case when b.IDDocumento is null then '0' else b.IDDocumento end IDTipoDocumento, 
x.IDTipoDocumento IDDocumento, tpers_id IDAlumno, 
tdocu_desc Documento,  
case when tstdo_desc is null then 'PENDIENTE'
     else  tstdo_desc end estatus,
 fecha(date_format(tredo_fecha_limite,'%Y-%m-%d')) limite,
     Descripcion,comentarios_documento(IDDocumento) Comentarios,
CONCAT(CAST(TamanoMinimo AS CHAR(10)) , ' KB') AS Minimo,           
  CONCAT(CAST(TamanoMaximo AS CHAR(10)) + ' KB') AS Maximo,           
  x.Formato            
from tpers  inner join tadmi a on tadmi_tpers_num = tpers_num  
inner join tredo on tredo_tpers_num = tadmi_tpers_num and tredo_tpees_clave = tadmi_tpees_clave      
and tredo_consecutivo = tadmi_consecutivo and tredo_estatus='A'
inner join tdocu on tredo_tdocu_clave=tdocu_clave and tdocu_estatus='A' 
inner join tprog on tprog_clave = tadmi_tprog_clave  
inner join TipoDocumento x on id_saes=tdocu_clave
LEFT JOIN Documentos_Alumno b ON  IDAlumno = tpers_id and x.IDTipoDocumento=b.IDTipoDocumento 
inner join tstdo on tstdo_clave=tredo_tstdo_clave  
where tpers_id = IDAlumno_in 
order by tadmi_consecutivo desc, tadmi_tpees_clave, Documento;

END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for Obtener_ListaEstatus_D
-- ----------------------------
DROP PROCEDURE IF EXISTS `Obtener_ListaEstatus_D`;
delimiter ;;
CREATE PROCEDURE `Obtener_ListaEstatus_D`(IN IDRol_in int,
IN IDTipoDocumento_in int)
BEGIN
SELECT A.IDEstatus,A.Nombre
FROM Estatus A
WHERE Agrupador='DOCUMENTOS'
AND A.IDEstatus NOT IN (SELECT IDEstatus FROM Permisos_Documentos_Estatus WHERE IDRol=IDRol_in AND IDTipoDocumento=IDTipoDocumento_in)
AND A.IDEstatus NOT IN ('3','4','17');
END
;;
delimiter ;

