BEGIN
Select IDTipoDocumento,Nombre,Descripcion,tamanominimo,tamanomaximo,Formato,Forzoso      
From TipoDocumento a, tdocu
where id_saes=tdocu_clave and tdocu_estatus='A'
ORDER BY   Nombre;
END
