-- ----------------------------
-- Procedure structure for P_ACTUALIZA_KARDEX_ALUMNO
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_ACTUALIZA_KARDEX_ALUMNO`;
delimiter ;;
CREATE PROCEDURE `P_ACTUALIZA_KARDEX_ALUMNO`(IN P_TPERS_NUM INT,
                                                  IN P_TPROG_CLAVE     VARCHAR(10),
                                                  IN P_TPEES_CLAVE_OLD VARCHAR(6),
                                                  IN P_TPEES_CLAVE_NEW VARCHAR(6),
                                                  IN P_TMATE_CLAVE_OLD VARCHAR(10),
                                                  IN P_TMATE_CLAVE_NEW VARCHAR(10),
                                                  IN P_TGRUP_CLAVE_OLD VARCHAR(6),
                                                  IN P_TGRUP_CLAVE_NEW VARCHAR(6),
                                                  IN P_TTIPO_CLAVE_OLD VARCHAR(2),
                                                  IN P_TTIPO_CLAVE_NEW VARCHAR(2),
                                                  IN P_TCALI_CLAVE_OLD VARCHAR(6),
                                                  IN P_TCALI_CLAVE_NEW VARCHAR(6),
                                                  IN P_COMMENTS VARCHAR(100),
                                                  IN P_USER  VARCHAR(30))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: OBTENER LAS MATERIAS QUE NO ESTA ACREDITADAS DEL ALUMNO

      CREADO: JCM
      FECHA: 11/09/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
    */
    
    DECLARE VL_RESPUESTA  VARCHAR(200);
    DECLARE L_TCAMP_CLAVE VARCHAR(2);
    DECLARE L_CONSE_MATE INT;
    DECLARE L_CONTAR     INT;
    

    
    IF P_TPERS_NUM IS NULL OR P_TPERS_NUM ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBES DE SELECIONAR UN ALUMNO PARA CONSULTAR');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    IF P_TPROG_CLAVE IS NULL OR P_TPROG_CLAVE ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBES DE SELECIONAR UN PROGRAMA PARA CONSULTAR');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    
    IF P_TPEES_CLAVE_OLD IS NULL OR P_TPEES_CLAVE_OLD ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBE DE SELECCIONAR UN PERIODO ');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    IF P_TMATE_CLAVE_OLD IS NULL OR P_TMATE_CLAVE_OLD ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBE DE SELECCIONAR UNA MATERIA ');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    IF P_TGRUP_CLAVE_OLD IS NULL OR P_TGRUP_CLAVE_OLD ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBE DE SELECCIONAR UNA GRUPO ');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    
    IF P_TTIPO_CLAVE_OLD IS NULL OR P_TTIPO_CLAVE_OLD ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBE DE SELECCIONAR UN TIPO');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    IF P_TCALI_CLAVE_OLD IS NULL OR P_TCALI_CLAVE_OLD ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBE DE SELECCIONAR UNA  CALIFICACION');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    SELECT DISTINCT TADMI_TCAMP_CLAVE
    INTO L_TCAMP_CLAVE
    FROM TADMI
    WHERE 1 = 1
    AND TADMI_TPERS_NUM = P_TPERS_NUM
    AND TADMI_TPROG_CLAVE = P_TPROG_CLAVE;
    
    
    SELECT COUNT(*)
    INTO L_CONTAR
    FROM TKARD
    WHERE 1 = 1
    AND TKARD_TPERS_NUM   = P_TPERS_NUM
    AND TKARD_TPROG_CLAVE = P_TPROG_CLAVE
    AND TKARD_TCAMP_CLAVE = L_TCAMP_CLAVE
    AND TKARD_TPEES_CLAVE = P_TPEES_CLAVE_OLD
    AND TKARD_TMATE_CLAVE = P_TMATE_CLAVE_OLD
    AND TKARD_TGRUP_CLAVE = P_TGRUP_CLAVE_OLD;
    
    IF L_CONTAR > 0 THEN
      
        UPDATE  TKARD SET TKARD_TPEES_CLAVE = P_TPEES_CLAVE_NEW,
                          TKARD_TMATE_CLAVE = P_TMATE_CLAVE_NEW,
                          TKARD_TGRUP_CLAVE = P_TGRUP_CLAVE_NEW,
                          TKARD_TTIPO_CLAVE = P_TTIPO_CLAVE_NEW,
                          TKARD_TCALI_CLAVE = P_TCALI_CLAVE_NEW,
                          TKARD_USER        = P_USER,
                          TKARD_DATE        = now()
        WHERE 1 = 1
        AND TKARD_TPERS_NUM   = P_TPERS_NUM
        AND TKARD_TPROG_CLAVE = P_TPROG_CLAVE
        AND TKARD_TCAMP_CLAVE = L_TCAMP_CLAVE
        AND TKARD_TPEES_CLAVE = P_TPEES_CLAVE_OLD
        AND TKARD_TMATE_CLAVE = P_TMATE_CLAVE_OLD
        AND TKARD_TGRUP_CLAVE = P_TGRUP_CLAVE_OLD;
        
        select  IFNULL(MAX(TKARA_CONS),0)+1
        INTO L_CONSE_MATE
        FROM TKARA
        WHERE 1 = 1
        AND TKARA_TPERS_NUM   = P_TPERS_NUM
        AND TKARA_TCAMP_CLAVE = L_TCAMP_CLAVE
        AND TKARA_TPROG_CLAVE = P_TPROG_CLAVE
        AND TKARA_TPEES_CLAVE = P_TPEES_CLAVE_OLD
        AND TKARA_TMATE_CLAVE = P_TMATE_CLAVE_OLD
        AND TKARA_TGRUP_CLAVE = P_TGRUP_CLAVE_OLD;
      
     
        select P_TPERS_NUM,
               P_TPEES_CLAVE_OLD,
               P_TPEES_CLAVE_NEW,
               L_TCAMP_CLAVE,
               P_TMATE_CLAVE_OLD,
               P_TMATE_CLAVE_NEW,
               P_TGRUP_CLAVE_OLD,
               P_TGRUP_CLAVE_NEW,
               P_TTIPO_CLAVE_OLD,
               P_TCALI_CLAVE_OLD,
               L_CONSE_MATE,
               P_COMMENTS,
               P_USER;
        
        
                           TKARA_TPEES_CLAVE,
                           TKARA_TCAMP_CLAVE,
                           TKARA_TPROG_CLAVE,
                           TKARA_TMATE_CLAVE,
                           TKARA_TGRUP_CLAVE,
                           TKARA_TTIPO_CLAVE,
                           TKARA_TCALI_CLAVE,
                           TKARA_CONS,
                           TKARA_COMMENTS,
                           TKARA_USER,
                           TKARA_DATE)
            VALUES
            (
              P_TPERS_NUM,
              P_TPEES_CLAVE_NEW,
              L_TCAMP_CLAVE,
              P_TPROG_CLAVE,
              P_TMATE_CLAVE_OLD,
              P_TGRUP_CLAVE_OLD,
              P_TTIPO_CLAVE_OLD,
              P_TCALI_CLAVE_OLD,
              L_CONSE_MATE,
              P_COMMENTS,
              P_USER,
              NOW()
            );
    ELSE
      
      SET VL_RESPUESTA = CONCAT('EL ALUMNO ',P_TPERS_NUM,' CON EL CAMPUS ',L_TCAMP_CLAVE,' CON EL PERIODO ',P_TPEES_CLAVE_OLD,' CON EL PROGRAMA ',P_TPROG_CLAVE,' CON LA NATERIA ',P_TMATE_CLAVE_OLD,' CON EL GRUPO ',P_TGRUP_CLAVE_OLD,' NO ENCONTRO RELACION');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
            
    END IF;  
  
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_ACTU_TTIAC
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_ACTU_TTIAC`;
delimiter ;;
CREATE PROCEDURE `P_ACTU_TTIAC`(IN P_CLAVE_OLD  VARCHAR(3),
                                        IN P_CLAVE      VARCHAR(3),
                                        IN P_DESC       VARCHAR(60),
                                        IN P_USER       VARCHAR(30),
                                        IN P_CLAVE_CERT VARCHAR(2),
                                        IN P_SIGLAS     VARCHAR(10),
                                        IN P_ESTATUS    VARCHAR(1))
BEGIN
     /*
      EMPRESA: COREMO SOLUCIONES TECNOLOGíCAS
      CREADO: JRO
      FECHA: 01/10/2022
      VERSIóN 1.0
      PROYECTO: DESARROLLO SAES
    
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
    */

    
    UPDATE TTIAC 
       SET TTIAC_CLAVE      = IFNULL(P_CLAVE,TTIAC_CLAVE),
           TTIAC_DESC       = IFNULL(P_DESC,TTIAC_DESC), 
           TTIAC_USER       = IFNULL(P_USER,TTIAC_USER), 
           TTIAC_CLAVE_CERT = IFNULL(P_CLAVE_CERT,TTIAC_CLAVE_CERT),
           TTIAC_SIGLAS     = IFNULL(P_SIGLAS,TTIAC_SIGLAS),  
           TTIAC_DATE       = current_timestamp(), 
           TTIAC_ESTATUS    = IFNULL(P_ESTATUS,TTIAC_ESTATUS)
    WHERE TTIAC_CLAVE = P_CLAVE_OLD;            
            

END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_BORRAR_OPTI
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_BORRAR_OPTI`;
delimiter ;;
CREATE PROCEDURE `P_BORRAR_OPTI`(IN P_CLAVE_OPTI  VARCHAR(2))
BEGIN
     /*
      EMPRESA: COREMO SOLUCIONES TECNOLOGíCAS
      CREADO: JRO
      FECHA: 18/09/2022
      VERSIóN 1.0
      PROYECTO: DESARROLLO SAES
    
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
    */

    
    DELETE FROM TTIOP WHERE TTIOP_CLAVE = P_CLAVE_OPTI;
            
    DELETE FROM TTINI WHERE TTINI_TTIOP_CLAVE = P_CLAVE_OPTI;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_BORRA_ACTUALIZA_INSS
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_BORRA_ACTUALIZA_INSS`;
delimiter ;;
CREATE PROCEDURE `P_BORRA_ACTUALIZA_INSS`(IN P_PERIODO VARCHAR(7), IN P_CAMPUS VARCHAR(3), IN P_MATERIA VARCHAR(10), IN P_GRUPO VARCHAR(6), 
																	  IN P_FECHA VARCHAR  (10))
BEGIN

	    /*
        
        P_PERS_ID Matricua del alumno
        P_USER id del usuario logueado

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: CREADO PARA GUARDAR LO ENVIADO DESDE EL DATAGRID DE LA FORMA TINS (Registro de inasistencias). 

      CREADO: MDE
      FECHA: 02/09/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
      
    */
    
		BEGIN
		DELETE FROM TINSS
				WHERE TINSS_TPEES_CLAVE=P_PERIODO 
				AND TINSS_TCAMP_CLAVE=P_CAMPUS
				AND TINSS_TMATE_CLAVE=P_MATERIA 
				AND TINSS_TGRUP_CLAVE=P_GRUPO
				AND TINSS_FECHA_IN=P_FECHA;
		 END;
         COMMIT;
		 
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_CODIGO_COCO
