-- ----------------------------
-- Procedure structure for P_DATOS_ALUMNOS
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_DATOS_ALUMNOS`;
delimiter ;;
CREATE PROCEDURE `P_DATOS_ALUMNOS`()
BEGIN
          
		BEGIN
		select distinct tpers_id AS clave, 
		tpers_nombre as nombre, 
		tpers_paterno as paterno, 
		tpers_materno as materno, 
		tpers_genero as c_genero, 
		CASE WHEN tpers_genero = 'F' 
		THEN 'Femenino' 
        WHEN tpers_genero = 'M' 
		THEN 'Masculino' 
		ELSE 'No Aplica' 
		END as genero,
		tpers_edo_civ as c_civil, 
		CASE WHEN tpers_edo_civ = 'C' 
        THEN 'Casado' 
		WHEN tpers_edo_civ = 'S' 
		THEN 'Soltero' 
		WHEN tpers_edo_civ = 'V' 
		THEN 'Viudo' 
        WHEN tpers_edo_civ = 'U' 
		THEN 'Union Libre' 
        WHEN tpers_edo_civ = 'D' 
		THEN 'Divorciado' 
        ELSE 'No Aplica' 
		END as e_civil, 
        tpers_curp as curp, 
		date_format(tpers_fecha_nac, ' %d/%m/%Y') as fecha, 
		tpers_usuario usuario, fecha(date_format(tpers_date, '%Y-%m-%d')) as fecha_reg
		from tpers
		where tpers_tipo = 'E';
		END;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_DATOS_FUNCIONARIO_TCEEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_DATOS_FUNCIONARIO_TCEEL`;
delimiter ;;
CREATE PROCEDURE `P_DATOS_FUNCIONARIO_TCEEL`(IN P_MATRICULA VARCHAR(10), IN P_PROGRAMA VARCHAR(10))
BEGIN

	/*
    EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
    PROCEDIMIENTO: CREADO PARA RETORNAR EN TCEEL INFORMACIÓN DEl FUNCIONARIO .
    CREADO: MDE
    FECHA: 05/10/2022
    VERSIÓN 1.0
    PROYECTO: DESARROLLO SAES
   */
   
	   
	-- Datos Funcionario
	select tfuca_nombre nombre, 
			tfuca_paterno primerApellido, 
            tfuca_materno segundoApellido, 
			tfuca_curp curp , 
            tfuca_desc, 
            tfuca_clave idCargo
	from testu s, tfuca
	where tfuca_clave='5'
	and testu_tpers_num in (select tpers_num 
							from tpers 
                            where tpers_id=P_MATRICULA) -- 'U99203594')
	and testu_tprog_clave=P_PROGRAMA -- 'ADP032016M'
	and testu_tpees_clave in (select max(testu_tpees_clave) 
							  from testu ss
							  where s.testu_tpers_num=ss.testu_tpers_num 
                              and s.testu_tprog_clave=ss.testu_tprog_clave)
	and testu_tcamp_clave=tfuca_tcamp_clave;

   END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_DATOS_MATERIA_TCEEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_DATOS_MATERIA_TCEEL`;
delimiter ;;
CREATE PROCEDURE `P_DATOS_MATERIA_TCEEL`(IN P_MATRICULA VARCHAR(10), IN P_PROGRAMA VARCHAR(10))
BEGIN

	/*
    EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
    PROCEDIMIENTO: CREADO PARA RETORNAR EN TCEEL INFORMACIÓN DE LAS MATERIAS EN KARDEX .
    CREADO: MDE
    FECHA: 05/10/2022
    VERSIÓN 1.0
    PROYECTO: DESARROLLO SAES
   */
   
	   
	-- Datos Materias
		select tkard_tmate_clave, 
        tmate_clave_incorp idAsignatura,
        tmate_desc, 
        tkard_tpees_clave, 
        tpees_ofic ciclo,
		tkard_tcali_clave calificacion, 
        ttiac_clave_cert idObservaciones, 
        ttiac_desc,
        tplan_tmate_tipo idTipoAsignatura,
		case when tplan_tmate_clave='263' then 
        'OBLIGATORIA' 
        else 'OPTATIVA' end tipo_mate,
		tmate_creditos creditos
		from tkard, tmate, tpees, ttiac, tplan
		where tkard_tpers_num in (select tpers_num from tpers where tpers_id=P_MATRICULA) -- 'U99203594')
		and   tkard_tprog_clave= P_PROGRAMA -- 'ADP032016M'
		and   tkard_tmate_clave=tmate_clave
		and   tkard_tpees_clave=tpees_clave
		and   tkard_ttipo_clave=ttiac_clave
		and   tplan_tprog_clave=tkard_tprog_clave 
        and tplan_tmate_clave=tkard_tmate_clave;

   END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for p_dml_porcentaje
-- ----------------------------
DROP PROCEDURE IF EXISTS `p_dml_porcentaje`;
delimiter ;;
CREATE PROCEDURE `p_dml_porcentaje`(IN `p_periodo`    varchar(6),
                                    in `p_campus`     varchar(3),
                                    IN `p_nivel`      varchar(2),
                                    in `p_porcentaje` decimal(6,1),
                                    in `p_fecha_ini`  date,
                                    in `p_fecha_fin`  date,
                                    in  `p_user`      VARCHAR(50))
begin
    DECLARE l_contar int;
    declare l_retorna varchar(200);
    SET l_retorna ='EXITO';
    
  begin
  
    if p_fecha_ini = p_fecha_fin then
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'Las fechas no pueden ser las mismas'; 
    
    end if;
    
    IF p_fecha_ini > p_fecha_fin THEN
      
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'La fecha de inicio no puede ser mayor a la fecha fin';    
    
    END IF;
    
    
    select count(*)
    into l_contar
    from TBAPA
    where 1 = 1
    and TBAPA_TPEES_CLAVE = p_periodo
    and TBAPA_TCAMP_CLAVE = p_campus
    and TBAPA_TNIVE_CLAVE = p_nivel
    and ((p_fecha_ini between TBAPA_FECHA_INI and TBAPA_FECHA_FIN or p_fecha_fin between TBAPA_FECHA_INI and TBAPA_FECHA_FIN)
	        or (p_fecha_ini <= TBAPA_FECHA_INI and p_fecha_fin >= TBAPA_FECHA_FIN)
	        or (p_fecha_ini >= TBAPA_FECHA_INI and p_fecha_fin <= TBAPA_FECHA_FIN)
	      );   
    
    if l_contar > 0 then
      
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'No se puede tener la misma configuración entre varios rangos de fechas';    
      
    end if;
    
    set l_contar= 0;
    
    select count(*)
    into l_contar
    from TBAPA
    where 1 = 1
    and TBAPA_TPEES_CLAVE = p_periodo
    and TBAPA_TCAMP_CLAVE = p_campus
    and TBAPA_TNIVE_CLAVE = p_nivel
    and TBAPA_PORCEN = p_porcentaje;
    
    
    if  l_contar = 0 then
    
                         TBAPA_TCAMP_CLAVE,
                         TBAPA_TNIVE_CLAVE,
                         TBAPA_PORCEN,
                         TBAPA_FECHA_INI,
                         TBAPA_FECHA_FIN,
                         TBAPA_USER,
                         TBAPA_DATE
                         )values 
                         (p_periodo,
                          p_campus,
                          p_nivel,
                          p_porcentaje,
                          p_fecha_ini,
                          p_fecha_fin,
                          p_user,
                          now()
                          );
    
    else
      
      update TBAPA set TBAPA_PORCEN      = p_porcentaje,
                       TBAPA_FECHA_INI   = p_fecha_ini,
                       TBAPA_FECHA_FIN   = p_fecha_fin,
                       TBAPA_DATE = now()
      where 1 = 1
      and TBAPA_TPEES_CLAVE =p_periodo
      and TBAPA_TCAMP_CLAVE = p_campus
      and TBAPA_TNIVE_CLAVE = p_nivel
      and TBAPA_PORCEN = p_porcentaje;                 
      
    end if;
      
  end;
    
  commit;       
  
  if l_retorna <>'EXITO' then
  
    signal sqlstate'45000' set message_text='El registro esta duplicado';
    
  end if;
  
  select l_retorna;

end
;;
delimiter ;

