-- ----------------------------
-- Procedure structure for P_INSERTA_CALI
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_INSERTA_CALI`;
delimiter ;;
CREATE PROCEDURE `P_INSERTA_CALI`(IN P_PERIODO  VARCHAR(7),
                                        IN P_CAMPUS   VARCHAR(3),
                                        IN P_NIVEL    VARCHAR(3),
                                        IN P_PROGRAMA VARCHAR(15),
                                        IN P_MATERIA  VARCHAR(7),
                                        IN P_GRUPO    VARCHAR(5),
                                        IN P_USER     VARCHAR(20))
BEGIN
    /*
      EMPRESA: COREMO SOLUCIONES TECNOLOGíCAS
      CREADO: JRO
      FECHA: 18/08/2022
      VERSIóN 1.0
      PROYECTO: DESARROLLO SAES
    
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
    */

  DECLARE done INT DEFAULT FALSE;
  
  DECLARE VL_ALUMNO   INT;
  DECLARE VL_ENTRA    INT;
  DECLARE VL_PERIODO  VARCHAR(7);
  DECLARE VL_CAMPUS   VARCHAR(3);
  DECLARE VL_NIVEL    VARCHAR(3);
  DECLARE VL_PROGRAMA VARCHAR(12);
  DECLARE VL_MATERIA  VARCHAR(7);
  DECLARE VL_GRUPO    VARCHAR(5);
  DECLARE VL_CALI     DECIMAL(4,2);
  DECLARE VL_TERMINO  VARCHAR(100);
  DECLARE VL_CONTADOR INT;
  DECLARE X_COMP VARCHAR(2); DECLARE X_CALIF VARCHAR(6);
  DECLARE C_REP decimal(3,2);
  DECLARE C_DEF varchar(6);
      
  DECLARE CALIF CURSOR FOR SELECT TCACX_TPEES_CLAVE,TCACX_TCAMP_CLAVE,TPROG_TNIVE_CLAVE,TCACX_TPROG_CLAVE,TCACX_TMATE_CLAVE,TCACX_TGRUP_CLAVE,TCACX_TPERS_NUM
                             FROM TCACX,TPROG
                            WHERE     TPROG_CLAVE = TCACX_TPROG_CLAVE
                                  AND IFNULL(P_PERIODO,TCACX_TPEES_CLAVE) = TCACX_TPEES_CLAVE
                                  AND IFNULL(P_CAMPUS,TCACX_TCAMP_CLAVE) = TCACX_TCAMP_CLAVE
                                  AND IFNULL(P_NIVEL,TPROG_TNIVE_CLAVE) = TPROG_TNIVE_CLAVE
                                  AND IFNULL(P_PROGRAMA,TCACX_TPROG_CLAVE) = TCACX_TPROG_CLAVE
                                  AND IFNULL(P_MATERIA,TCACX_TMATE_CLAVE) = TCACX_TMATE_CLAVE
                                  AND IFNULL(P_GRUPO,TCACX_TGRUP_CLAVE) = TCACX_TGRUP_CLAVE
                            GROUP BY TCACX_TPEES_CLAVE,TCACX_TCAMP_CLAVE,TPROG_TNIVE_CLAVE,TCACX_TPROG_CLAVE,TCACX_TMATE_CLAVE,TCACX_TGRUP_CLAVE, TCACX_TPERS_NUM;
 
  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
  
  SET VL_CONTADOR = 0;
  
  OPEN CALIF;

  read_loop: LOOP
    
    FETCH CALIF INTO VL_PERIODO,VL_CAMPUS,VL_NIVEL,VL_PROGRAMA,VL_MATERIA,VL_GRUPO,VL_ALUMNO;
    
    IF done THEN
      LEAVE read_loop;
    END IF;
    
    BEGIN
    
		select count(*)into X_COMP
		from tcocx
		where 1 = 1
		and   (tcocx_tnive_clave=VL_NIVEL or tcocx_tnive_clave='00')
		and   (tcocx_tcamp_clave=VL_CAMPUS or tcocx_tcamp_clave='000')
		and   (tcocx_tprog_clave=VL_PROGRAMA or tcocx_tprog_clave='0000000000')
		and   (tcocx_tmate_clave=VL_MATERIA or tcocx_tmate_clave='000000');
        
        select count(*) into X_CALIF from tcacx 
	   where tcacx_tpees_clave=VL_PERIODO and tcacx_tpers_num=VL_ALUMNO 
	   and tcacx_tcamp_clave=VL_CAMPUS and tcacx_tmate_clave=VL_MATERIA and tcacx_tgrup_clave=VL_GRUPO
	   and tcacx_tcali_clave is not null;
    
    END;
    /* Si tiene todas las calificaciones capturadas de acuerdo a la configuración */
    if X_COMP = X_CALIF then
    
		BEGIN
		  SELECT COUNT(*)
			INTO VL_ENTRA
			FROM TKARD
		   WHERE     TKARD_TPERS_NUM = VL_ALUMNO
				 AND TKARD_TMATE_CLAVE = VL_MATERIA
				 AND TKARD_TPEES_CLAVE = VL_PERIODO;
		END;
		/* Obtienen la calificación mínima por Nivel */
        BEGIN
        
			select max(tcali_puntos) into C_REP from tcali
			where tcali_tnive_clave=VL_NIVEL and tcali_ind_aprob='N';
        
        END;
        /*Obtiene Calificación definitiva */
		BEGIN
			SELECT SUM(TCACX_TCALI_CLAVE*(TCOCX_PORCENTAJE/100) ) AS CALIFICACION
			  INTO VL_CALI
			  FROM TCACX,TCOCX,TPROG
			 WHERE     TCOCX_TNIVE_CLAVE = TPROG_TNIVE_CLAVE
				   AND TCACX_TCOMP_CLAVE = TCOCX_TCOMP_CLAVE
				   AND TPROG_CLAVE = TCACX_TPROG_CLAVE
				   AND TCACX_TPERS_NUM = VL_ALUMNO
				   AND TCACX_TMATE_CLAVE = VL_MATERIA
				   AND TCACX_TPROG_CLAVE = VL_PROGRAMA
				   AND TCACX_TCAMP_CLAVE = VL_CAMPUS
				   AND TCACX_TPEES_CLAVE = VL_PERIODO;
		  END;
          
          if VL_CALI < C_REP then
			SET VL_CALI=C_REP;
		  else
             SET VL_CALI=ROUND(VL_CALI);
          end if;
          
          BEGIN
          
			SELECT TCALI_CLAVE INTO C_DEF FROM TCALI
            WHERE TCALI_TNIVE_CLAVE=VL_NIVEL AND TCALI_PUNTOS=VL_CALI;
          
          END;
		
		IF VL_ENTRA = 0 THEN
		  
		  BEGIN 
			 insert 
			   into `tkard`(`tkard_tpers_num`,
							`tkard_tpees_clave`,
							`tkard_tcamp_clave`,
							`tkard_tprog_clave`,
							`tkard_tmate_clave`,
							`tkard_tgrup_clave`,
							`tkard_ttipo_clave`,
							`tkard_tcali_clave`,
							`tkard_user`,
							`tkard_date`) 
			 values (VL_ALUMNO,
					 VL_PERIODO,
					 VL_CAMPUS,
					 VL_PROGRAMA,
					 VL_MATERIA,
					 VL_GRUPO,
					 'OR',
					 C_DEF,
					 P_USER,
					 SYSDATE());
		  END;
		  
		  SET VL_CONTADOR = VL_CONTADOR+1;
		  
		ELSE
		  UPDATE TKARD
			 SET TKARD_TCALI_CLAVE = VL_CALI,
				 TKARD_DATE = SYSDATE(),
				 TKARD_USER = P_USER
		   WHERE     TKARD_TPERS_NUM = VL_ALUMNO
				 AND TKARD_TMATE_CLAVE = VL_MATERIA
				 AND TKARD_TPEES_CLAVE = VL_PERIODO;
		  
		  SET VL_CONTADOR = VL_CONTADOR+1;
		  
		END IF;
    
    END IF;
    
  END LOOP;

  CLOSE CALIF;
  IF VL_CONTADOR > 0 THEN
    SET VL_TERMINO = CONCAT('PROCESO TERMINADO CORRECTAMENTE, NUMERO DE CALIFICACIONES PROCESADAS = ',VL_CONTADOR); 
  
  ELSE
    SET VL_TERMINO = CONCAT('PROCESO TERMINADO SIN REGISTROS'); 
  END IF;
   
  SELECT VL_TERMINO AS P_INSERTA_CALI;
  
  COMMIT;
END
;;
delimiter ;

