-- ----------------------------
-- Procedure structure for P_INSERTA_KARDEX_ALUMNO
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_INSERTA_KARDEX_ALUMNO`;
delimiter ;;
CREATE PROCEDURE `P_INSERTA_KARDEX_ALUMNO`(IN P_TPERS_NUM INT,
                                            IN P_TPROG_CLAVE VARCHAR(10),
                                            IN P_TPEES_CLAVE VARCHAR(6),
                                            IN P_TMATE_CLAVE VARCHAR(10),
                                            IN P_TGRUP_CLAVE VARCHAR(6),
                                            IN P_TTIPO_CLAVE VARCHAR(2),
                                            IN P_TCALI_CLAVE VARCHAR(6),
                                            IN P_USER  VARCHAR(30))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: OBTENER LAS MATERIAS QUE NO ESTA ACREDITADAS DEL ALUMNO

      CREADO: JCM
      FECHA: 11/09/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
    */
    
    DECLARE VL_RESPUESTA  VARCHAR(100);
    DECLARE L_TCAMP_CLAVE VARCHAR(2);
    DECLARE L_CONSE_MATE  INT;

    
    IF P_TPERS_NUM IS NULL OR P_TPERS_NUM ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBES DE SELECIONAR UN ALUMNO PARA CONSULTAR');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    IF P_TPROG_CLAVE IS NULL OR P_TPROG_CLAVE ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBES DE SELECIONAR UN PROGRAMA PARA CONSULTAR');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    
    IF P_TPEES_CLAVE IS NULL OR P_TPEES_CLAVE ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBE DE SELECCIONAR UN PERIODO ');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    IF P_TMATE_CLAVE IS NULL OR P_TMATE_CLAVE ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBE DE SELECCIONAR UNA MATERIA ');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    IF P_TGRUP_CLAVE IS NULL OR P_TGRUP_CLAVE ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBE DE SELECCIONAR UNA GRUPO ');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    
    IF P_TTIPO_CLAVE IS NULL OR P_TTIPO_CLAVE ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBE DE SELECCIONAR UN TIPO');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    IF P_TCALI_CLAVE IS NULL OR P_TCALI_CLAVE ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBE DE SELECCIONAR UNA  CALIFICACION');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    SELECT DISTINCT TADMI_TCAMP_CLAVE
    INTO L_TCAMP_CLAVE
    FROM TADMI
    WHERE 1 = 1
    AND TADMI_TPERS_NUM = P_TPERS_NUM
    AND TADMI_TPROG_CLAVE = P_TPROG_CLAVE;
    
    -- IF L_TCAMP_CLAVE IS NOT NULL THEN
      
      
      /*  
        select P_TPERS_NUM,
               P_TPEES_CLAVE,
               L_TCAMP_CLAVE,
               P_TMATE_CLAVE,
               P_TGRUP_CLAVE,
               P_TTIPO_CLAVE,
               P_TCALI_CLAVE,
               L_CONSE_MATE,
               P_COMMENTS,
               P_USER;
        */
        
        
        
                          tkard_tpees_clave,
                          tkard_tcamp_clave,
                          tkard_tprog_clave,
                          tkard_tmate_clave,
                          tkard_tgrup_clave,
                          tkard_ttipo_clave,
                          tkard_tcali_clave,
                          tkard_user,
                          tkard_date)
            VALUES
            (
              P_TPERS_NUM,
              P_TPEES_CLAVE,
              L_TCAMP_CLAVE,
              P_TPROG_CLAVE,
              P_TMATE_CLAVE,
              P_TGRUP_CLAVE,
              P_TTIPO_CLAVE,
              P_TCALI_CLAVE,
              P_USER,
              NOW()
            );
      
  
END
;;
delimiter ;

