-- ----------------------------
-- Procedure structure for P_INSERTA_TTINI
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_INSERTA_TTINI`;
delimiter ;;
CREATE PROCEDURE `P_INSERTA_TTINI`(IN P_CLAVE_OPTI  VARCHAR(2),
                                      -- IN P_DESC        VARCHAR(90),
                                      -- IN P_ESTATUS     VARCHAR(1),
                                      IN P_USER        VARCHAR(30),
                                      IN P_NIVEL       VARCHAR(3),
