           (TTINI_TTIOP_CLAVE,TTINI_TNIVE_CLAVE,TTINI_CREDITOS,TTINI_PROMEDIO,TTINI_TCOCO_CLAVE,TTINI_TUSER_CLAVE,TTINI_DATE) 
    VALUES (P_CLAVE_OPTI,
            P_NIVEL,
            P_CREDITOS,
            P_PROMEDIO,
            P_CLAVE_COCO,
            P_USER,
            current_timestamp());   

END
;;
delimiter ;

