-- ----------------------------
-- Procedure structure for P_OBTEN_ACREDITACION
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_ACREDITACION`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_ACREDITACION`(IN P_NADA VARCHAR(1))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: PARA OBTENER VALORES DE ACREDITACION

      CREADO: JCM
      FECHA: 11/09/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
    */
    -- QUERY EN LO QUE SE HACE LA PANTALLA DE PARAMETROS
    SELECT 'OR' ACREDITA,
           'ORDINARIO' DESCRIPCION
    UNION
    SELECT 'MO' ACREDITA,
           'MODIFICACION' DESCRIPCION
    UNION       
    SELECT 'EX' ACREDITA,
           'EXTRAORDINARIO' DESCRIPCION;       

END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_ALUMNOS
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_ALUMNOS`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_ALUMNOS`(IN P_PERIODO VARCHAR(6), IN P_CAMPUS VARCHAR(3), IN P_MATERIA VARCHAR(10), IN P_GRUPO VARCHAR(6), IN P_COMPONENTE VARCHAR(3))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: CREADO PARA RETORNAR LOS ALUMNOS EN EL DATAGRID EN LA FORMA TCOCX.

      CREADO: MDE
      FECHA: 29/08/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
      
    */

    DECLARE CLAVE   VARCHAR(6);
    DECLARE COMPNENTE   VARCHAR(50);
  DECLARE VL_CONTADOR   INT;
    DECLARE VL_RESPUESTA   VARCHAR(100);
    
    
      SET VL_CONTADOR =  NULL;
    BEGIN
      SELECT  COUNT(TPERS_ID)
            INTO VL_CONTADOR
        FROM TTIRA  
        INNER JOIN TPERS ON TTIRA_TPERS_NUM = TPERS_NUM  
        INNER JOIN  TPROG ON TTIRA_TPROG_CLAVE = TPROG_CLAVE  
        LEFT OUTER JOIN TCACX ON TCACX_TPEES_CLAVE = TTIRA_TPEES_CLAVE AND TCACX_TCAMP_CLAVE = TTIRA_TCAMP_CLAVE  
        AND TCACX_TMATE_CLAVE = TTIRA_TMATE_CLAVE AND TCACX_TGRUP_CLAVE = TTIRA_TGRUP_CLAVE AND TTIRA_TPERS_NUM = TCACX_TPERS_NUM  
        WHERE TTIRA_TPEES_CLAVE = P_PERIODO
        AND   TTIRA_TMATE_CLAVE = P_MATERIA
        AND   TTIRA_TGRUP_CLAVE = P_GRUPO
        AND   TTIRA_TCAMP_CLAVE = P_CAMPUS;   
      END;
      
      IF VL_CONTADOR = 0 THEN
     SIGNAL SQLSTATE '45000'
         SET MESSAGE_TEXT = 'Consulta sin datos'; 
         
      ELSEIF VL_CONTADOR != 0 THEN

     BEGIN       
      SELECT  TPERS_ID MATRICULA, 
            CONCAT(TPERS_NOMBRE,' ',TPERS_PATERNO,' ',TPERS_MATERNO) NOMBRE,  
      TTIRA_TPROG_CLAVE CLAVE, 
            TPROG_DESC NOM_PROGRAMA,  
      (SELECT TCACX_TCALI_CLAVE 
          FROM TCACX  
          WHERE TCACX_TPEES_CLAVE = TTIRA_TPEES_CLAVE 
                    AND TCACX_TCAMP_CLAVE = TTIRA_TCAMP_CLAVE  
          AND TCACX_TMATE_CLAVE = TTIRA_TMATE_CLAVE
                    AND TCACX_TGRUP_CLAVE = TTIRA_TGRUP_CLAVE  
          AND TTIRA_TPERS_NUM = TCACX_TPERS_NUM  
          AND TCACX_TCOMP_CLAVE = P_COMPONENTE)
                    CALIFICACION,  
      (SELECT FECHA(DATE_FORMAT(TCACX_DATE, '%Y-%m-%d')) 
          FROM TCACX  
          WHERE TCACX_TPEES_CLAVE = TTIRA_TPEES_CLAVE AND TCACX_TCAMP_CLAVE = TTIRA_TCAMP_CLAVE  
          AND TCACX_TMATE_CLAVE = TTIRA_TMATE_CLAVE AND TCACX_TGRUP_CLAVE = TTIRA_TGRUP_CLAVE  
          AND TTIRA_TPERS_NUM = TCACX_TPERS_NUM  
          AND TCACX_TCOMP_CLAVE = P_COMPONENTE) 
          FECHA  
          FROM TTIRA  
      INNER JOIN TPERS ON TTIRA_TPERS_NUM = TPERS_NUM  
      INNER JOIN  TPROG ON TTIRA_TPROG_CLAVE = TPROG_CLAVE  
      LEFT OUTER JOIN TCACX ON TCACX_TPEES_CLAVE = TTIRA_TPEES_CLAVE AND TCACX_TCAMP_CLAVE = TTIRA_TCAMP_CLAVE  
      AND TCACX_TMATE_CLAVE = TTIRA_TMATE_CLAVE AND TCACX_TGRUP_CLAVE = TTIRA_TGRUP_CLAVE AND TTIRA_TPERS_NUM = TCACX_TPERS_NUM  
      WHERE TTIRA_TPEES_CLAVE = P_PERIODO
      AND   TTIRA_TMATE_CLAVE = P_MATERIA
      AND   TTIRA_TGRUP_CLAVE = P_GRUPO
      AND   TTIRA_TCAMP_CLAVE = P_CAMPUS
      ORDER BY 2;
      END;
     
  END IF;

END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_ALUMNOS_INSCRITOS
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_ALUMNOS_INSCRITOS`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_ALUMNOS_INSCRITOS`(IN P_PERIODO VARCHAR(7), IN P_CAMPUS VARCHAR(3), IN P_MATERIA VARCHAR(10), IN P_GRUPO VARCHAR(6), IN P_FECHA VARCHAR  (10))
BEGIN

	    /*
        
        P_PERS_ID Matricua del alumno
        P_USER id del usuario logueado

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: CREADO PARA MOSTRAR EN LA FORMA TINS (Registro de inasistencias) LOS ALUMNOS INSCRITOS EN EL GRUPO 

      CREADO: MDE
      FECHA: 02/09/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
      
    */
	
	SELECT TPERS_ID MATRICULA, CONCAT(TPERS_NOMBRE,' ',TPERS_PATERNO,' ',TPERS_MATERNO) NOMBRE ,  
	TTIRA_TPROG_CLAVE CLAVE, TPROG_DESC NOM_PROGRAMA,  
	(SELECT 'I' FROM TINSS  
	WHERE TINSS_TPEES_CLAVE = TTIRA_TPEES_CLAVE AND TINSS_TCAMP_CLAVE = TTIRA_TCAMP_CLAVE  
	AND TINSS_TMATE_CLAVE = TTIRA_TMATE_CLAVE AND TINSS_TGRUP_CLAVE = TTIRA_TGRUP_CLAVE  
	AND TTIRA_TPERS_NUM = TINSS_TPERS_NUM  
	AND TINSS_FECHA_IN = P_FECHA) INASISTENCIA  
	FROM TTIRA  
	INNER JOIN TPERS ON TTIRA_TPERS_NUM = TPERS_NUM  
	INNER JOIN  TPROG ON TTIRA_TPROG_CLAVE = TPROG_CLAVE  
	LEFT OUTER JOIN TCACX ON TCACX_TPEES_CLAVE = TTIRA_TPEES_CLAVE AND TCACX_TCAMP_CLAVE = TTIRA_TCAMP_CLAVE  
	AND TCACX_TMATE_CLAVE = TTIRA_TMATE_CLAVE AND TCACX_TGRUP_CLAVE = TTIRA_TGRUP_CLAVE AND TTIRA_TPERS_NUM = TCACX_TPERS_NUM  
	WHERE TTIRA_TPEES_CLAVE = P_PERIODO
	AND   TTIRA_TMATE_CLAVE = P_MATERIA
	AND   TTIRA_TGRUP_CLAVE = P_GRUPO
	AND   TTIRA_TCAMP_CLAVE = P_CAMPUS
	ORDER BY 2 ;
            
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_ALUMNO_PROGRAMA
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_ALUMNO_PROGRAMA`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_ALUMNO_PROGRAMA`(IN P_TPERS_NUM INT)
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: OBTENER PROGRAMA POR ALUMNO

      CREADO: JCM
      FECHA: 11/09/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
    */
    -- QUERY EN LO QUE SE HACE LA PANTALLA DE PARAMETROS
  
  DECLARE L_CONTAR           INT;  
  DECLARE VL_RESPUESTA       VARCHAR(100);
  
  SET L_CONTAR =  NULL;
  
  SELECT COUNT(*)
  INTO L_CONTAR
  FROM TPERS A
  JOIN TESTU B ON A.TPERS_NUM = B.TESTU_TPERS_NUM
  JOIN TPROG C ON C.TPROG_CLAVE = B.TESTU_TPROG_CLAVE
  WHERE 1 = 1
  AND A.TPERS_NUM = P_TPERS_NUM;
  
  IF L_CONTAR > 0 THEN
  
    SELECT DISTINCT TPROG_CLAVE PROGRAMA,
                    UPPER(TPROG_DESC) DESCRIPCION
    FROM TPERS A
    JOIN TESTU B ON A.TPERS_NUM = B.TESTU_TPERS_NUM
    JOIN TPROG C ON C.TPROG_CLAVE = B.TESTU_TPROG_CLAVE
    WHERE 1 = 1
    AND A.TPERS_NUM = P_TPERS_NUM;
    
  ELSE
  
    SET VL_RESPUESTA = CONCAT('ESTA PERSONA NO TIENE UN PROGRAMA ASIGNADO, FAVOR DE VALIDAR');
    
    SIGNAL SQLSTATE '45000'
    SET MESSAGE_TEXT = VL_RESPUESTA;
  
  END IF;
  
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_ALUMNO_TCEEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_ALUMNO_TCEEL`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_ALUMNO_TCEEL`(IN P_MATRICULA VARCHAR(10))
BEGIN

	/*
    EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
    PROCEDIMIENTO: CREADO PARA RETORNAR EN LA FORMA TCEEL LOS DATOS DEL ALUMNO.
    CREADO: MDE
    FECHA: 05/10/2022
    VERSIÓN 1.0
    PROYECTO: DESARROLLO SAES
   */
   
   
    select tpers_nombre nombre, 
    tpers_paterno primerApellido, 
    tpers_materno segundoApellido, 
	case when tpers_genero = 'M' THEN
		'251'
	when tpers_genero = 'F' THEN
		'250'
	END
    idGenero,
	case when tpers_genero = 'M' THEN
		'HOMBRE'
	when tpers_genero = 'F' THEN
		'MUJER'
	END
    genero,
	DATE_FORMAT(tpers_fecha_nac, '%d/%m/%Y') fechaNacimiento,
    tpers_curp curp
	from tpers
	where tpers_id=P_MATRICULA; -- 'U99203594';
   END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_BITACORA_KARDEX
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_BITACORA_KARDEX`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_BITACORA_KARDEX`(IN P_TPERS_NUM INT,
                                          IN P_TPROG_CLAVE VARCHAR(10),
                                          IN P_TPEES_CLAVE VARCHAR(6),
                                          IN P_TMATE_CLAVE VARCHAR(10))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: OBTENER LAS MATERIAS QUE NO ESTA ACREDITADAS DEL ALUMNO

      CREADO: JCM
      FECHA: 19/09/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
    */
    
    DECLARE VL_RESPUESTA  VARCHAR(100);
    DECLARE L_TCAMP_CLAVE VARCHAR(2);
    DECLARE L_CONTAR      INT;

    
    IF P_TPERS_NUM IS NULL OR P_TPERS_NUM ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBES DE SELECIONAR UN ALUMNO PARA CONSULTAR');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    IF P_TPROG_CLAVE IS NULL OR P_TPROG_CLAVE ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBES DE SELECIONAR UN PROGRAMA PARA CONSULTAR');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    
    IF P_TMATE_CLAVE IS NULL OR P_TMATE_CLAVE ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBES DE SELECIONAR UNA MATERIA PARA CONSULTAR');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    
       
    

        SELECT DISTINCT TESTU_TCAMP_CLAVE
        INTO L_TCAMP_CLAVE
        FROM TESTU A
        WHERE 1 = 1
        AND A.TESTU_TPERS_NUM = P_TPERS_NUM
        AND A.TESTU_TPROG_CLAVE = P_TPROG_CLAVE
        AND A.TESTU_TPEES_CLAVE = (SELECT MAX(B.TESTU_TPEES_CLAVE)
                                   FROM TESTU B
                                   WHERE 1 = 1
                                   AND A.TESTU_TPERS_NUM = B.TESTU_TPERS_NUM
                                   AND A.TESTU_TPROG_CLAVE = B.TESTU_TPROG_CLAVE);
      
    
        SELECT TKARA_CONS CONSECUTIVO, 
               TKARA_TCALI_CLAVE CALIFICACION,
               CASE WHEN TKARA_TTIPO_CLAVE ='OR' THEN 'ORDINARIO'
                    WHEN TKARA_TTIPO_CLAVE ='MO' THEN 'MODIFICACION'
                    WHEN TKARA_TTIPO_CLAVE ='AC' THEN 'ACREDITACION'
               END   ACREDITACION,
               ifnull(tuser_desc,TKARA_USER) USUARIO,
               TKARA_DATE FECHA,
               TKARA_COMMENTS COMENTARIO
        FROM TKARA a 
        left JOIN tuser b on  b.tuser_clave = a.TKARA_USER
        WHERE 1 = 1
        AND TKARA_TPERS_NUM   = P_TPERS_NUM
        AND TKARA_TPEES_CLAVE = P_TPEES_CLAVE 
        AND TKARA_TCAMP_CLAVE = L_TCAMP_CLAVE
        AND TKARA_TPROG_CLAVE = P_TPROG_CLAVE
        AND TKARA_TMATE_CLAVE = P_TMATE_CLAVE
        ORDER BY 1,2;
  
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_BORRA_ACTUALIZA
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_BORRA_ACTUALIZA`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_BORRA_ACTUALIZA`(IN P_PERIODO VARCHAR(7), IN P_CAMPUS VARCHAR(3), IN P_MATERIA VARCHAR(10), IN P_GRUPO VARCHAR(6),
										   IN P_COMPONENTE VARCHAR(3), IN P_PERS_ID VARCHAR(10), IN P_CLAVE_PROG VARCHAR(10), IN P_CALI_CLAVE VARCHAR(6), IN P_USER VARCHAR(20))
BEGIN

	    /*
        
        P_PERS_ID Matricua del alumno
        P_USER id del usuario logueado

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: CREADO PARA GUARDAR Y ACTUALIZAR EL REGISTRO DE CALIFICACIONES INGRESADAS DESDE  TCACX

      CREADO: MDE
      FECHA: 01/09/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
      
    */

	
	  BEGIN
      
      DELETE  FROM TCACX 
      WHERE TCACX_TPEES_CLAVE=P_PERIODO
      AND TCACX_TCAMP_CLAVE=P_CAMPUS 
      AND TCACX_TMATE_CLAVE=P_MATERIA
      AND TCACX_TGRUP_CLAVE=P_GRUPO  
      AND TCACX_TCOMP_CLAVE=P_COMPONENTE
      AND TCACX_TPERS_NUM IN (SELECT TPERS_NUM 
							  FROM TPERS
                              WHERE TPERS_ID = P_PERS_ID);
      END;
      
	BEGIN
       VALUES(P_PERIODO,
          P_CAMPUS,
          P_MATERIA,
          P_GRUPO,
          P_COMPONENTE, 
          (SELECT TPERS_NUM 
          FROM TPERS 
          WHERE TPERS_ID=P_PERS_ID),
          P_CLAVE_PROG,
          P_CALI_CLAVE,
          P_USER, 
          CURRENT_TIMESTAMP());
      END;
            
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_CALI
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_CALI`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_CALI`(IN P_PROGRAMA VARCHAR(10))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: CREADO PARA RETORNAR EL LISTADO DE CALIFICACIONES EN EL DATAGRID DE LA FORMA COCX.

      CREADO: MDE
      FECHA: 29/08/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
      
    */


  DECLARE VL_CONTADOR   INT;
    DECLARE VL_RESPUESTA   VARCHAR(100);
    
    SET VL_CONTADOR = NULL;
        BEGIN
      SELECT COUNT(TCALI_CLAVE)
            INTO  VL_CONTADOR
            FROM TPROG, TCALI  
      WHERE TPROG_CLAVE=P_PROGRAMA 
            AND TCALI_TNIVE_CLAVE=TPROG_TNIVE_CLAVE;
        END;
        
        IF VL_CONTADOR = 0 THEN
      SIGNAL SQLSTATE '45000'
          SET MESSAGE_TEXT = 'Consulta sin datos'; 
          
        ELSEIF VL_CONTADOR != 0 THEN

     BEGIN
       
      SELECT TCALI_CLAVE CALI, 
            TCALI_PUNTOS PUNTOS 
            FROM TPROG, TCALI  
      WHERE TPROG_CLAVE=P_PROGRAMA 
            AND TCALI_TNIVE_CLAVE=TPROG_TNIVE_CLAVE  
      UNION 
      SELECT '---' CALI, 0 PUNTOS FROM DUAL 
      ORDER BY PUNTOS;
      END;
      
  END IF;
            
END
;;
delimiter ;

