delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_CAMPUS_DOCENTE
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_CAMPUS_DOCENTE`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_CAMPUS_DOCENTE`(IN P_USER  VARCHAR(20), IN P_PERIODO  VARCHAR(7))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: CREADO PARA RETORNAR EN LA FORMA TCOCX LOS CAMPUS ASOCIADOS AL PORFESOR LOGUEADO EN SAES.

      CREADO: MDE
      FECHA: 29/08/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
      
    */

    DECLARE CLAVE   VARCHAR(3);
    DECLARE CAMPUS    VARCHAR(60);
    DECLARE VL_CONTADOR   INT;
    DECLARE VL_RESPUESTA   VARCHAR(100);
    
    -- VALIDA QUE EXISTA EL USUARIO --
    SET VL_CONTADOR = NULL;        
    BEGIN
      SELECT COUNT(*)
            INTO VL_CONTADOR
            FROM TUSER
            WHERE 1=1
            AND TUSER_CLAVE = P_USER;      
        END;
        
    IF VL_CONTADOR = 0 OR P_USER IS NULL THEN
    SIGNAL SQLSTATE '45000'
    SET MESSAGE_TEXT = 'Usuario no registrado'; 
    END IF;
    
    -- VALIDA DATOS CON LOS PARÁMETROS ENVIADOS --
    SET VL_CONTADOR = NULL;        
    BEGIN
      SELECT COUNT(*)
      INTO VL_CONTADOR
      FROM TCAMP, THODO, TPERS 
      WHERE TPERS_ID=P_USER
      AND   THODO_TPERS_NUM=TPERS_NUM AND THODO_ESTATUS='A' 
      AND   THODO_TPEES_CLAVE=P_PERIODO
      AND   THODO_TCAMP_CLAVE=TCAMP_CLAVE;
        END;
    
     IF VL_CONTADOR = 0 THEN
      SELECT '000' CLAVE, 'Campus' CAMPUS;
          
     ELSEIF VL_CONTADOR !=0 THEN
    
       BEGIN
        SELECT TCAMP_CLAVE CLAVE, TCAMP_DESC  CAMPUS
        FROM TCAMP, THODO, TPERS 
        WHERE TPERS_ID=P_USER
        AND   THODO_TPERS_NUM=TPERS_NUM AND THODO_ESTATUS='A' 
        AND   THODO_TPEES_CLAVE=P_PERIODO
        AND   THODO_TCAMP_CLAVE=TCAMP_CLAVE
        ORDER BY CLAVE;
      END;
          
      END IF;
            
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_CAMPUS_TCEEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_CAMPUS_TCEEL`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_CAMPUS_TCEEL`(IN P_MATRICULA VARCHAR(10), IN P_PROGRAMA VARCHAR(10))
BEGIN

	/*
    EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
    PROCEDIMIENTO: CREADO PARA RETORNAR EN TCEEL INFORMACIÓN DEl CAMPUS DEL ALUMNO .
    CREADO: MDE
    FECHA: 05/10/2022
    VERSIÓN 1.0
    PROYECTO: DESARROLLO SAES
   */
   
	   
-- Datos Campus
	select tcamp_incorp IdCampus, 
		   tcamp_testa_clave IdEntidadFederativa,
           tcamp_clave,
           tcamp_desc
	from testu s, tcamp
	where testu_tpers_num in (select tpers_num 
							  from tpers 
                              where tpers_id=P_MATRICULA) -- 'U99203594')
	and	  testu_tprog_clave=P_PROGRAMA -- 'ADP032016M'
	and   testu_tpees_clave in (select max(testu_tpees_clave) 
								from testu ss
								where s.testu_tpers_num=ss.testu_tpers_num 
                                and s.testu_tprog_clave=ss.testu_tprog_clave)
	and   testu_tcamp_clave=tcamp_clave;

   END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_COMPONENTE
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_COMPONENTE`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_COMPONENTE`(IN P_MATERIA VARCHAR(10))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: CREADO PARA RETORNAR EN LA FORMA TCOCX LOS COMPONENTES O PARCIALES DE UN GRUPO MATERIA.

      CREADO: MDE
      FECHA: 29/08/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
      
    */


    DECLARE CLAVE   VARCHAR(6);
    DECLARE COMPNENTE   VARCHAR(50);
    DECLARE VL_CONTADOR   INT;
    DECLARE VL_RESPUESTA   VARCHAR(100);
    
BEGIN       
	SELECT TCOCX_TCOMP_CLAVE CLAVE , TCOMP_DESC COMPONENTE
    FROM TCOCX, TCACX, TPLAN, TPROG, TCOMP
    WHERE TCACX_TMATE_CLAVE=P_MATERIA
    AND   TPLAN_TMATE_CLAVE=TCACX_TMATE_CLAVE
    AND   TPROG_CLAVE=TPLAN_TPROG_CLAVE   
    AND   (TCOCX_TNIVE_CLAVE=TPROG_TNIVE_CLAVE OR TCOCX_TNIVE_CLAVE='00')
    AND   (TCOCX_TCAMP_CLAVE=TCACX_TCAMP_CLAVE OR TCOCX_TCAMP_CLAVE='000')
    AND   (TCOCX_TPROG_CLAVE=TPROG_CLAVE OR TCOCX_TPROG_CLAVE='0000000000')
    AND   (TCOCX_TMATE_CLAVE=TCACX_TMATE_CLAVE OR TCOCX_TMATE_CLAVE='000000')
    AND    TCOCX_TCOMP_CLAVE=TCOMP_CLAVE
    GROUP BY CLAVE, COMPONENTE
    UNION SELECT '000000' CLAVE , 'Componente' COMPONENTE;
END;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_CREDITOS_TCEEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_CREDITOS_TCEEL`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_CREDITOS_TCEEL`(IN P_MATRICULA VARCHAR(10), IN P_PROGRAMA VARCHAR(10))
BEGIN

	/*
    EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
    PROCEDIMIENTO: CREADO PARA RETORNAR EN TCEEL EL PROMEDIO DEL ALUMNO .
    CREADO: MDE
    FECHA: 05/10/2022
    VERSIÓN 1.0
    PROYECTO: DESARROLLO SAES
   */
   
	   
-- Creditos
	select sum(tmate_creditos) creditosObtenidos 
    from tkard, tcali, tprog, tmate
	where tkard_tpers_num in (select tpers_num 
							  from tpers 
                              where tpers_id=P_MATRICULA) -- 'U99203594')
	and tkard_tprog_Clave=P_PROGRAMA -- 'ADP032016M'
	and tkard_tprog_clave=tprog_clave 
    and tkard_tprog_clave=tprog_clave
	and tprog_tnive_clave=tcali_tnive_clave 
    and tkard_tcali_clave=tcali_clave
	and tcali_ind_aprob='S' 
    and tmate_clave=tkard_tmate_clave;

   END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_DATOS_ALUMNO_TTIEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_DATOS_ALUMNO_TTIEL`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_DATOS_ALUMNO_TTIEL`(IN P_MATRICULA VARCHAR(10), IN P_PROGRAMA VARCHAR(10))
BEGIN

	/*
    EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
    PROCEDIMIENTO: CREADO PARA RETORNAR LOS DATOS DEL ALUMNO POR PORGRAMA EN TTIEL.
    CREADO: MDE
    FECHA: 05/10/2022
    VERSIÓN 1.0
    PROYECTO: DESARROLLO SAES
   */
   
	-- Datos alumno-programa
		select 
		tfuca_nombre func_nombre, 
		tfuca_paterno func_primerApellido, 
		tfuca_materno func_segundoApellido, 
		tfuca_curp curp , 
		tfuca_desc, 
		tfuca_clave idCargo,
		'' noCertificadoResponsable , 
		'' abrTitulo, 
		tcamp_incorp cveInstitucion ,
		tcamp_clave cveInstitucionAbreb ,
		tcamp_desc nombreInstitucionReal,
		'UNIVERSIDAD COREMO' nombreInstitucion,
		tprog_incorporante cveCarrera,
		tprog_desc nombreCarrera,
		(select date_format(min(tpees_inicio),'%d/%m/%Y') 
        from tpees, tkard k
		where tkard_tpers_num=tpers_num 
        and tkard_tprog_clave=testu_tprog_clave 
		and tkard_tcamp_clave=testu_tcamp_clave) fechaInicio,
		(select date_format(max(tpees_inicio),'%d/%m/%Y') 
        from tpees, tkard k
		where tkard_tpers_num=tpers_num 
        and tkard_tprog_clave=testu_tprog_clave 
		and tkard_tcamp_clave=testu_tcamp_clave) fechaTerminacion,
		tpers_nombre nombre, 
		tpers_paterno primerApellido, 
		tpers_materno segundoApellido, 
		tpers_curp Profesionista_curp, 
		'titulos@universidad-coremo.edu.mx' correoElectronico,
		tprog_rvoe numeroRvoe,
		tcamp_testa_clave idEntidadFederativa,
		testa_desc entidadFederativa
		from tpers, testu s, tfuca, tcamp, tprog, testa
		where tpers_id='U99203594'
        and tfuca_clave='5'
		and testu_tpers_num=tpers_num
		and testu_tprog_clave='ADP032016M'
		and testu_tpees_clave in (select max(testu_tpees_clave) 
								 from testu ss
								 where s.testu_tpers_num=ss.testu_tpers_num 
                                 and s.testu_tprog_clave=ss.testu_tprog_clave)
		and testu_tcamp_clave=tfuca_tcamp_clave 
        and testu_tcamp_clave=tcamp_clave
		and testu_tprog_clave=tprog_clave 
        and tcamp_testa_clave=testa_clave;

        
   END
;;
delimiter ;

