-- ----------------------------
-- Procedure structure for P_OBTEN_FOLIO_TTIEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_FOLIO_TTIEL`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_FOLIO_TTIEL`(IN P_MATRICULA VARCHAR(10), IN P_PROGRAMA VARCHAR(10))
BEGIN

	/*
    EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
    PROCEDIMIENTO: CREADO PARA RETORNAR EL FOLIO DEL TITULO ELECTRÓNICO EN  TTIEL.
    CREADO: MDE
    FECHA: 05/10/2022
    VERSIÓN 1.0
    PROYECTO: DESARROLLO SAES
   */
   
		 declare vl_camp_clave varchar(3);
	
		 select testu_tcamp_clave
		 into vl_camp_clave
		 from testu s
		 where testu_tpers_num in (select tpers_num 
									  from tpers 
									  where tpers_id= P_MATRICULA) -- P_MATRICULA) -- 'U99203594')
			and testu_tprog_clave= P_PROGRAMA -- P_PROGRAMA -- 'ADP032016M'
			and testu_tpees_clave in (select max(testu_tpees_clave) 
									  from testu ss
									  where s.testu_tpers_num=ss.testu_tpers_num 
									  and s.testu_tprog_clave=ss.testu_tprog_clave);
                                  
		update tcseq set tcseq_numero = tcseq_numero+1
        where 
        tcseq_tcamp_clave = vl_camp_clave
        and tcseq_tseqn_clave = '010';		
   
	-- Obtiene número de folio
		select lpad(tcseq_numero,tcseq_longitud,'0') folio
		from tcseq, testu s
		where testu_tpers_num in (select tpers_num 
								  from tpers 
								  where tpers_id=P_MATRICULA) -- 'U99203594')
		and   testu_tprog_clave=P_PROGRAMA -- 'ADP032016M'
		and   testu_tpees_clave in (select max(testu_tpees_clave) from testu ss
									where s.testu_tpers_num=ss.testu_tpers_num 
									and s.testu_tprog_clave=ss.testu_tprog_clave)
		and testu_tcamp_clave=tcseq_tcamp_clave 
		and tcseq_tseqn_clave='010';
						
   END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_GRUPO
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_GRUPO`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_GRUPO`(IN P_CAMPUS   VARCHAR(3),
                                      IN P_NIVEL    VARCHAR(6),
                                      IN P_PROGRAMA VARCHAR(15),
                                      IN P_MATERIA  VARCHAR(15),
									  IN P_PERIODO  VARCHAR (6))
BEGIN
    /*
      EMPRESA: COREMO SOLUCIONES TECNOLOGíCAS
      CREADO: JRO
      FECHA: 18/08/2022
      VERSIóN 1.0
      PROYECTO: DESARROLLO SAES
    
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
    */
    
    DECLARE L_ERROR            VARCHAR(100);
    DECLARE L_CONTAR           INT;
    DECLARE VL_RESPUESTA       VARCHAR(100);
    
      BEGIN
      
      IF P_MATERIA IS NULL THEN
       SIGNAL SQLSTATE '45000'
          SET MESSAGE_TEXT = 'DEBES SELECCIONAR MATERIA PARA VISUALIZAR EL COMBO';
      ELSE
      
       SELECT COUNT(*)
        INTO L_CONTAR
        FROM TPROG a,
             TCAPR b,
             TPLAN c,
             TMATE d,
             TGRUP e
       WHERE a.TPROG_CLAVE = b.TCAPR_TPROG_CLAVE
       AND a.TPROG_CLAVE = c.TPLAN_TPROG_CLAVE
       AND c.TPLAN_TMATE_CLAVE = d.TMATE_CLAVE 
       and b.TCAPR_TCAMP_CLAVE = e.tgrup_tcamp_clave 
       and e.tgrup_tmate_clave = d.TMATE_CLAVE
       AND e.tgrup_tpees_clave = P_PERIODO
       AND IFNULL(P_CAMPUS,b.TCAPR_TCAMP_CLAVE)=b.TCAPR_TCAMP_CLAVE
       AND IFNULL(P_NIVEL,a.TPROG_TNIVE_CLAVE)=a.TPROG_TNIVE_CLAVE
       AND IFNULL(P_PROGRAMA,a.TPROG_CLAVE)=a.TPROG_CLAVE
       AND IFNULL(P_MATERIA,d.TMATE_CLAVE)=d.TMATE_CLAVE;
      
      
        IF L_CONTAR = 0  THEN
          
          BEGIN
            IF P_NIVEL IS NOT NULL AND P_CAMPUS IS NULL AND P_PROGRAMA IS NULL AND P_MATERIA IS NULL THEN
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL NIVEL ',P_NIVEL);
            
            ELSEIF P_NIVEL IS NOT NULL AND P_CAMPUS IS NULL AND P_PROGRAMA IS NULL AND P_MATERIA IS NOT NULL THEN
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL NIVEL ',P_NIVEL,' Y MATERIA ',P_MATERIA);
              
            ELSEIF P_NIVEL IS NOT NULL AND P_CAMPUS IS NOT NULL AND P_PROGRAMA IS NULL AND P_MATERIA IS NULL THEN
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL CAMPUS ',P_CAMPUS,' Y NIVEL ',P_NIVEL);
            
            ELSEIF P_NIVEL IS NOT NULL AND P_CAMPUS IS NOT NULL AND P_PROGRAMA IS NULL AND P_MATERIA IS NOT NULL THEN
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL CAMPUS ',P_CAMPUS,', NIVEL ',P_NIVEL,' Y MATERIA ',P_MATERIA );  
              
            ELSEIF P_NIVEL IS NULL AND P_CAMPUS IS NOT NULL AND P_PROGRAMA IS NULL AND P_MATERIA IS NULL THEN
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL CAMPUS ',P_CAMPUS);  
              
            ELSEIF P_NIVEL IS NULL AND P_CAMPUS IS NOT NULL AND P_PROGRAMA IS NULL AND P_MATERIA IS NOT NULL THEN
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL CAMPUS ',P_CAMPUS,' Y MATERIA ',P_MATERIA );    
              
            ELSEIF P_NIVEL IS NULL AND P_CAMPUS IS NOT NULL AND P_PROGRAMA IS NOT NULL AND P_MATERIA IS NULL THEN
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL CAMPUS ',P_CAMPUS,' Y PROGRAMA ',P_PROGRAMA);    
            
            ELSEIF P_NIVEL IS NULL AND P_CAMPUS IS NOT NULL AND P_PROGRAMA IS NOT NULL AND P_MATERIA IS NOT NULL THEN
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL CAMPUS ',P_CAMPUS,', PROGRAMA ',P_PROGRAMA,' Y MATERIA ',P_MATERIA );
              
            ELSEIF P_NIVEL IS NULL AND P_CAMPUS IS NULL AND P_PROGRAMA IS NOT NULL AND P_MATERIA IS NULL THEN
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL PROGRAMA ',P_PROGRAMA);    
            
            ELSEIF P_NIVEL IS NULL AND P_CAMPUS IS NULL AND P_PROGRAMA IS NOT NULL AND P_MATERIA IS NOT NULL THEN
            SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL PROGRAMA ',P_PROGRAMA,' Y MATERIA ',P_MATERIA );    
              
            ELSEIF P_NIVEL IS NOT NULL AND P_CAMPUS IS NULL AND P_PROGRAMA IS NOT NULL AND P_MATERIA IS NULL THEN
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL NIVEL ',P_NIVEL,' Y PROGRAMA',P_PROGRAMA);
            
            ELSEIF P_NIVEL IS NOT NULL AND P_CAMPUS IS NULL AND P_PROGRAMA IS NOT NULL AND P_MATERIA IS NOT NULL THEN
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL NIVEL ',P_NIVEL,', PROGRAMA',P_PROGRAMA,' Y MATERIA ',P_MATERIA );  
              
            ELSEIF P_CAMPUS IS NOT NULL AND P_NIVEL IS NOT NULL AND P_PROGRAMA IS NOT NULL AND P_MATERIA IS NULL THEN
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL CAMPUS ',P_CAMPUS,', NIVEL ',P_NIVEL,' Y PROGRAMA ',P_PROGRAMA);
              
            ELSEIF P_CAMPUS IS NOT NULL AND P_NIVEL IS NOT NULL AND P_PROGRAMA IS NOT NULL AND P_MATERIA IS NOT NULL THEN
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA EL CAMPUS ',P_CAMPUS,', NIVEL ',P_NIVEL,', PROGRAMA ',P_PROGRAMA,' Y MATERIA ',P_MATERIA );
            
            ELSEIF P_NIVEL IS NULL AND P_CAMPUS IS NULL AND P_PROGRAMA IS NULL AND P_MATERIA IS NOT NULL THEN
            SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO PARA LA MATERIA ',P_MATERIA);    
            ELSE
              SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA GRUPO ');
            END IF;
          END;
          
          SIGNAL SQLSTATE '45000'
          SET MESSAGE_TEXT = VL_RESPUESTA;
          
        ELSE
          
            SELECT DISTINCT
                   E.TGRUP_CLAVE       AS GRUPO
            FROM TPROG a,
                 TCAPR b,
                 TPLAN c,
                 TMATE d,
                 TGRUP e
           WHERE a.TPROG_CLAVE = b.TCAPR_TPROG_CLAVE
                  AND a.TPROG_CLAVE = c.TPLAN_TPROG_CLAVE
                  AND c.TPLAN_TMATE_CLAVE = d.TMATE_CLAVE 
                  and b.TCAPR_TCAMP_CLAVE = e.tgrup_tcamp_clave 
                  and e.tgrup_tmate_clave = d.TMATE_CLAVE
                  AND e.tgrup_tpees_clave = P_PERIODO
                  AND IFNULL(P_CAMPUS,b.TCAPR_TCAMP_CLAVE)=b.TCAPR_TCAMP_CLAVE
                  AND IFNULL(P_NIVEL,a.TPROG_TNIVE_CLAVE)=a.TPROG_TNIVE_CLAVE
                  AND IFNULL(P_PROGRAMA,a.TPROG_CLAVE)=a.TPROG_CLAVE
                  AND IFNULL(P_MATERIA,d.TMATE_CLAVE)=d.TMATE_CLAVE
            ORDER BY E.TGRUP_CLAVE;
        END IF;
      
      END IF;
  
  END;    
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_GRUPO_DOCENTE
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_GRUPO_DOCENTE`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_GRUPO_DOCENTE`(IN P_USER  VARCHAR(20),IN P_CAMPUS VARCHAR(3), IN P_PERIODO  VARCHAR(6), IN P_MATERIA VARCHAR(10))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: CREADO PARA RETORNAR EN LA FORMA TCOCX LOS GRUPOS ASOCIADAS A UN DOCENTE POR CAMPUS, PERIODO, MATERIA.

      CREADO: MDE
      FECHA: 29/08/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
      
    */


    DECLARE CLAVE   VARCHAR(6);
    DECLARE VL_CONTADOR   INT;
    DECLARE VL_RESPUESTA   VARCHAR(100);
        
        
        SET VL_CONTADOR = NULL;
    BEGIN
      SELECT COUNT(*) 
	  INTO VL_CONTADOR
      FROM    THODO, TPERS  
      WHERE   TPERS_ID=P_USER
      AND   THODO_TPERS_NUM=TPERS_NUM 
      AND   THODO_ESTATUS='A'  
      AND   THODO_TPEES_CLAVE=P_PERIODO
      AND   THODO_TCAMP_CLAVE=P_CAMPUS
      AND   THODO_TMATE_CLAVE=P_MATERIA;        
	END;
        
    IF VL_CONTADOR = 0 THEN

      SELECT '000000' CLAVE, 'Materia' Grupo ;
      
	ELSEIF  VL_CONTADOR != 0 THEN
		
      BEGIN       
      SELECT THODO_TGRUP_CLAVE CLAVE 
      FROM    THODO, TPERS  
      WHERE   TPERS_ID=P_USER
      AND   THODO_TPERS_NUM=TPERS_NUM 
      AND   THODO_ESTATUS='A'  
      AND   THODO_TPEES_CLAVE=P_PERIODO
      AND   THODO_TCAMP_CLAVE=P_CAMPUS
      AND   THODO_TMATE_CLAVE=P_MATERIA
    UNION  
      SELECT 'Grupo' CLAVE   
      ORDER BY CLAVE DESC ;    
       END;
       
       END IF;            

END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_KAREDEX_ALUMNO
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_KAREDEX_ALUMNO`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_KAREDEX_ALUMNO`(IN P_TPERS_NUM INT,
                                       IN P_TPROG_CLAVE VARCHAR(10))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: OBTENER LAS MATERIAS QUE NO ESTA ACREDITADAS DEL ALUMNO

      CREADO: JCM
      FECHA: 11/09/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
    */
    
    DECLARE VL_RESPUESTA  VARCHAR(100);
    DECLARE L_TCAMP_CLAVE VARCHAR(2);
    DECLARE L_CONTAR      INT;

    
    IF P_TPERS_NUM IS NULL OR P_TPERS_NUM ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBES DE SELECIONAR UN ALUMNO PARA CONSULTAR');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    IF P_TPROG_CLAVE IS NULL OR P_TPROG_CLAVE ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBES DE SELECIONAR UN PROGRAMA PARA CONSULTAR');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    SELECT DISTINCT TESTU_TCAMP_CLAVE
    INTO L_TCAMP_CLAVE
    FROM TESTU A
    WHERE 1 = 1
    AND A.TESTU_TPERS_NUM = P_TPERS_NUM
    AND A.TESTU_TPROG_CLAVE = P_TPROG_CLAVE
    AND A.TESTU_TPEES_CLAVE = (SELECT MAX(B.TESTU_TPEES_CLAVE)
                               FROM TESTU B
                               WHERE 1 = 1
                               AND A.TESTU_TPERS_NUM = B.TESTU_TPERS_NUM
                               AND A.TESTU_TPROG_CLAVE = B.TESTU_TPROG_CLAVE);
      
    
      SELECT DISTINCT B.TKARD_TPEES_CLAVE PERIODO,
                  B.TKARD_TMATE_CLAVE CLAVE,
                  UPPER(D.TMATE_DESC) MATERIA,
                  TKARD_TGRUP_CLAVE GRUPO,
                  B.TKARD_TCALI_CLAVE CALIFICACION,
                  B.TKARD_TTIPO_CLAVE ACREDITA,
                  B.TKARD_USER USUARIO,
                  B.TKARD_DATE FECHA,
                  (SELECT count(*) FROM TKARA a 
										WHERE 1 = 1
										AND TKARA_TPERS_NUM   = TKARD_TPERS_NUM
										AND TKARA_TPEES_CLAVE = B.TKARD_TPEES_CLAVE 
										AND TKARA_TCAMP_CLAVE = tkard_tcamp_clave
										AND TKARA_TPROG_CLAVE = TKARD_TPROG_CLAVE
										AND TKARA_TMATE_CLAVE = B.TKARD_TMATE_CLAVE ) VALOR_CONTAR
      FROM TKARD B
      JOIN TMATE D ON B.TKARD_TMATE_CLAVE = D.TMATE_CLAVE
      WHERE 1 = 1
      AND TKARD_TPERS_NUM =   P_TPERS_NUM
      AND TKARD_TPROG_CLAVE = P_TPROG_CLAVE
      AND tkard_tcamp_clave = L_TCAMP_CLAVE
      ORDER BY 1,2;
   
    
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_MATERIA
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_MATERIA`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_MATERIA`(IN P_CAMPUS   VARCHAR(3),
                                        IN P_NIVEL    VARCHAR(6),
                                        IN P_PROGRAMA VARCHAR(15))
BEGIN
    /*
      EMPRESA: COREMO SOLUCIONES TECNOLOGíCAS
      CREADO: JRO
      FECHA: 18/08/2022
      VERSIóN 1.0
      PROYECTO: DESARROLLO SAES
    
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
    */
    
    DECLARE L_ERROR            VARCHAR(100);
    DECLARE L_CONTAR           INT;
    DECLARE VL_RESPUESTA       VARCHAR(100);
    
    BEGIN
      SELECT COUNT(*)
        INTO L_CONTAR
        FROM TPROG,TCAPR,TPLAN
       WHERE     TPROG_CLAVE = TCAPR_TPROG_CLAVE
             AND TPROG_CLAVE = TPLAN_TPROG_CLAVE
             AND IFNULL(P_CAMPUS,TCAPR_TCAMP_CLAVE)=TCAPR_TCAMP_CLAVE
             AND IFNULL(P_NIVEL,TPROG_TNIVE_CLAVE)=TPROG_TNIVE_CLAVE
             AND IFNULL(P_PROGRAMA,TPROG_CLAVE)=TPROG_CLAVE;
    
    
      IF L_CONTAR = 0  THEN
        
        BEGIN
          IF P_NIVEL IS NOT NULL AND P_CAMPUS IS NULL AND P_PROGRAMA IS NULL THEN
            SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA MATERIA PARA EL NIVEL ',P_NIVEL);
            
          ELSEIF P_NIVEL IS NOT NULL AND P_CAMPUS IS NOT NULL AND P_PROGRAMA IS NULL THEN
            SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA MATERIA PARA EL CAMPUS ',P_CAMPUS,', Y NIVEL ',P_NIVEL);
            
          ELSEIF P_NIVEL IS NULL AND P_CAMPUS IS NOT NULL AND P_PROGRAMA IS NULL THEN
            SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA MATERIA PARA EL CAMPUS ',P_CAMPUS);  
            
          ELSEIF P_NIVEL IS NULL AND P_CAMPUS IS NOT NULL AND P_PROGRAMA IS NOT NULL THEN
            SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA MATERIA PARA EL CAMPUS ',P_CAMPUS,', Y PROGRAMA ',P_PROGRAMA);    
            
          ELSEIF P_NIVEL IS NULL AND P_CAMPUS IS NULL AND P_PROGRAMA IS NOT NULL THEN
            SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA MATERIA PARA EL PROGRAMA ',P_PROGRAMA);    
          
          ELSEIF P_NIVEL IS NOT NULL AND P_CAMPUS IS NULL AND P_PROGRAMA IS NOT NULL THEN
            SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA MATERIA PARA EL NIVEL ',P_NIVEL,' Y PROGRAMA',P_PROGRAMA);
            
          ELSEIF P_CAMPUS IS NOT NULL AND P_NIVEL IS NOT NULL AND P_PROGRAMA IS NOT NULL THEN
            SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA MATERIA PARA EL CAMPUS ',P_CAMPUS,', NIVEL ',P_NIVEL,' Y PROGRAMA ',P_PROGRAMA);
          ELSE
            SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA PROGRAMA ');
          END IF;
        END;
        
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = VL_RESPUESTA;
        
      ELSE
        
        SELECT DISTINCT
               TMATE_CLAVE       AS CLAVE,
               TMATE_DESC        AS DESCRIPCION_MATERIA
          FROM TPROG,TCAPR,TPLAN,TMATE
         WHERE     TPROG_CLAVE = TCAPR_TPROG_CLAVE
               AND TPROG_CLAVE = TPLAN_TPROG_CLAVE
               AND TPLAN_TMATE_CLAVE = TMATE_CLAVE 
               AND IFNULL(P_CAMPUS,TCAPR_TCAMP_CLAVE)=TCAPR_TCAMP_CLAVE
               AND IFNULL(P_NIVEL,TPROG_TNIVE_CLAVE)=TPROG_TNIVE_CLAVE
               AND IFNULL(P_PROGRAMA,TPROG_CLAVE)=TPROG_CLAVE
         ORDER BY TMATE_DESC;
      END IF;
  
  END;    
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_MATERIA_DOCENTE
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_MATERIA_DOCENTE`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_MATERIA_DOCENTE`(IN P_USER  VARCHAR(20),IN P_CAMPUS VARCHAR(3), IN P_PERIODO  VARCHAR(6))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: CREADO PARA RETORNAR EN LA FORMA TCOCX LAS MATERIAS ASOCIADAS A UN DOCENTE POR CAMPUS PERIODO.

      CREADO: MDE
      FECHA: 29/08/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
      
    */


    DECLARE CLAVE   VARCHAR(10);
    DECLARE MATE    VARCHAR(100);
    DECLARE VL_CONTADOR   INT;
    DECLARE VL_RESPUESTA   VARCHAR(100);
        

     BEGIN       
      SELECT TMATE_CLAVE CLAVE, TMATE_DESC MATE 
      FROM TMATE, THODO, TPERS  
      WHERE TPERS_ID=P_USER 
      AND   THODO_TPERS_NUM=TPERS_NUM AND THODO_ESTATUS='A'  
      AND   THODO_TPEES_CLAVE=P_PERIODO
      AND   ((THODO_TCAMP_CLAVE=P_CAMPUS AND P_CAMPUS IS NOT NULL) OR THODO_TCAMP_CLAVE = THODO_TCAMP_CLAVE)
      AND TMATE_CLAVE = THODO_TMATE_CLAVE
      -- AND (P_CAMPUS IS NULL OR  THODO_TCAMP_CLAVE = P_CAMPUS) 
      UNION
      SELECT '000000' CLAVE, 'Materia' MATE 
      ORDER BY CLAVE ;    
      END;


END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_MATERIA_PLPER
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_MATERIA_PLPER`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_MATERIA_PLPER`(IN P_TPERS_NUM INT,
                                        IN P_TPROG_CLAVE VARCHAR(10))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: OBTENER LAS MATERIAS QUE NO ESTA ACREDITADAS DEL ALUMNO

      CREADO: JCM
      FECHA: 11/09/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
    */
    
    DECLARE L_TCAMP_CLAVE VARCHAR(2);
    
    SELECT DISTINCT TADMI_TCAMP_CLAVE
    INTO L_TCAMP_CLAVE
    FROM TADMI
    WHERE 1 = 1
    AND TADMI_TPERS_NUM = P_TPERS_NUM
    AND TADMI_TPROG_CLAVE = P_TPROG_CLAVE;
    
    
    SELECT DISTINCT D.TMATE_CLAVE CLAVE,
                UPPER(D.TMATE_DESC) MATERIA
    FROM TPLAN A
    JOIN TMATE D ON A.TPLAN_TMATE_CLAVE = D.TMATE_CLAVE
    WHERE 1 = 1
    AND A.TPLAN_TPROG_CLAVE = P_TPROG_CLAVE 
    AND NOT EXISTS 
    (
      SELECT *
      FROM TKARD B
      JOIN TCALI C
      WHERE 1 = 1
      AND A.TPLAN_TMATE_CLAVE = B.TKARD_TMATE_CLAVE
      AND A.TPLAN_TPROG_CLAVE = B.TKARD_TPROG_CLAVE
      AND B.TKARD_TCALI_CLAVE= C.TCALI_CLAVE 
      AND C.TCALI_IND_APROB ='S'
      and c.tcali_tnive_clave = L_TCAMP_CLAVE
      AND B.TKARD_TPERS_NUM = P_TPERS_NUM
    )ORDER BY 2;
  
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_MATERIA_PROGRAMA
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_MATERIA_PROGRAMA`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_MATERIA_PROGRAMA`(P_TPROG_CLAVE VARCHAR(10))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
