    JOIN TMATE D ON A.TPLAN_TMATE_CLAVE = D.TMATE_CLAVE
    WHERE 1 = 1
    AND A.TPLAN_TPROG_CLAVE = P_TPROG_CLAVE
    order by 2,1;
    /*AND NOT EXISTS 
    (
      SELECT *
      FROM TKARD B
      JOIN TCALI C
      WHERE 1 = 1
      AND A.TPLAN_TMATE_CLAVE = B.TKARD_TMATE_CLAVE
      AND A.TPLAN_TPROG_CLAVE = B.TKARD_TPROG_CLAVE
      AND B.TKARD_TCALI_CLAVE= C.TCALI_CLAVE 
      AND C.TCALI_IND_APROB ='S'
      AND B.TKARD_TPERS_NUM = P_TPERS_NUM
    )ORDER BY 2;*/
  
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_MATRICULA
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_MATRICULA`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_MATRICULA`(IN P_MATRICULA VARCHAR(10))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: PARA BUSCAR LA MATRICULA DEL ALUMNO SI ES QUE EXISTE

      CREADO: JCM
      FECHA: 11/09/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
    */

  DECLARE VL_CONTADOR   INT;
  DECLARE VL_RESPUESTA       VARCHAR(100);
   
   
   -- VALIDAMOS QUE LA MATRICULA NO VENGA NULA
  IF  P_MATRICULA  IS NULL THEN
  
    SET VL_RESPUESTA = 'EL VALOR DE MATRICULA ES NULO';
    
    SIGNAL SQLSTATE '45000'
    SET MESSAGE_TEXT = VL_RESPUESTA;
  
  END IF;
  
  
  -- CONTAMOS SI LA MATRICULA EXISTE EN LA BASE DE DATOS
  SET VL_CONTADOR =  NULL;
  
	SELECT COUNT(*)
  INTO VL_CONTADOR
	FROM TPERS
	WHERE 1 = 1
	AND UPPER(CONCAT(TPERS_ID,' ',tpers_nombre,' ',tpers_paterno,' ',tpers_materno)) like CONCAT('%',UPPER(P_MATRICULA),'%');
  
  
  IF VL_CONTADOR = 0 THEN
  
    SET VL_RESPUESTA = CONCAT('ESTA PERSONA CON LA BUSQUEDA --> ',P_MATRICULA,' NO EXISTE, FAVOR DE VALIDAR');
    
    SIGNAL SQLSTATE '45000'
    SET MESSAGE_TEXT = VL_RESPUESTA;
      
  ELSE
    
		SELECT DISTINCT TPERS_NUM NUMERO,
           TPERS_ID MATRICULA,
           TPERS_ID ID,
           TPERS_PATERNO PATERNO,
           TPERS_MATERNO MATERNO,
           TPERS_NOMBRE NOMBRE
           -- CONCAT('[',TPERS_ID,']',' ',TPERS_PATERNO,' ',TPERS_MATERNO,' ',TPERS_NOMBRE) NOMBRE
		FROM TPERS
		WHERE 1 = 1
		AND UPPER(CONCAT(TPERS_ID,' ',tpers_nombre,' ',tpers_paterno,' ',tpers_materno)) like CONCAT('%',UPPER(P_MATRICULA),'%')
		ORDER BY 3;
    
  END IF;

END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for p_obten_nivel
-- ----------------------------
DROP PROCEDURE IF EXISTS `p_obten_nivel`;
delimiter ;;
CREATE PROCEDURE `p_obten_nivel`(IN `p_campus` VARCHAR(2))
begin
    DECLARE l_contar           int;

  begin   
      if p_campus is null then
      
         select distinct tnive_clave clave, 
                      tnive_desc descripcion
          from tnive;
        
      else
      
          select distinct tnive_clave clave, 
                      tnive_desc descripcion
          from tcapr, tprog, tnive
          where 1 = 1
          AND TCAPR_TCAMP_CLAVE = p_campus
          and tcapr_tprog_clave=tprog_clave
          and tprog_tnive_clave=tnive_clave;
      
      end if;
  end;

END
;;
delimiter ;

