-- ----------------------------
-- Procedure structure for P_OBTEN_PERIODOS_TCEEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_PERIODOS_TCEEL`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_PERIODOS_TCEEL`(IN P_MATRICULA VARCHAR(10), IN P_PROGRAMA VARCHAR(10))
BEGIN

	/*
    EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
    PROCEDIMIENTO: CREADO PARA RETORNAR EN TCEEL EL TOTAL DE PERIODOS CURSADOS .
    CREADO: MDE
    FECHA: 05/10/2022
    VERSIÓN 1.0
    PROYECTO: DESARROLLO SAES
   */
   
	   
-- Periodos
	select count(distinct tpees_ofic) numeroCiclos 
    from tkard, tcali, tprog, tpees
	where tkard_tpers_num in (select tpers_num 
							  from tpers 
                              where tpers_id=P_MATRICULA) -- 'U99203594')
	and tkard_tprog_Clave=P_PROGRAMA-- 'ADP032016M'
	and tkard_tprog_clave=tprog_clave 
    and tkard_tprog_clave=tprog_clave
	and tprog_tnive_clave=tcali_tnive_clave 
    and tkard_tcali_clave=tcali_clave
	and tcali_ind_aprob='S' 
    and tpees_clave=tkard_tpees_clave;

   END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_PROGRAMA
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_PROGRAMA`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_PROGRAMA`(IN P_CAMPUS   VARCHAR(3),
                                         IN P_NIVEL    VARCHAR(6))
BEGIN
    /*
      EMPRESA: COREMO SOLUCIONES TECNOLOGíCAS
      CREADO: JRO
      FECHA: 18/08/2022
      VERSIóN 1.0
      PROYECTO: DESARROLLO SAES
    
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
    */
    
    DECLARE L_ERROR            VARCHAR(100);
    DECLARE L_CONTAR           INT;
    DECLARE VL_RESPUESTA       VARCHAR(300);
    
    BEGIN
      SELECT COUNT(*)
        INTO L_CONTAR
        FROM TPROG,TCAPR
       WHERE     TPROG_CLAVE = TCAPR_TPROG_CLAVE
             AND IFNULL(P_CAMPUS,TCAPR_TCAMP_CLAVE)=TCAPR_TCAMP_CLAVE
             AND IFNULL(P_NIVEL,TPROG_TNIVE_CLAVE)=TPROG_TNIVE_CLAVE; 
    
    
      IF L_CONTAR = 0  THEN
        IF P_CAMPUS IS NOT NULL AND P_NIVEL IS NULL THEN
          SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA PROGRAMA PARA EL CAMPUS ',P_CAMPUS);
        ELSEIF P_NIVEL IS NOT NULL AND P_CAMPUS IS NULL THEN
          SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA PROGRAMA PARA EL NIVEL ',P_NIVEL);
        
        ELSEIF P_NIVEL IS NOT NULL AND P_CAMPUS IS NOT NULL THEN
          SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA PROGRAMA PARA EL CAMPUS ',P_CAMPUS,' Y NIVEL ',P_NIVEL);
          
        ELSE
          SET VL_RESPUESTA = 'NO SE ENCUENTRA PROGRAMA';
        END IF;
      
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = VL_RESPUESTA;
        
      ELSE
        SELECT TPROG_CLAVE,TPROG_DESC
          FROM TPROG,TCAPR
         WHERE     TPROG_CLAVE = TCAPR_TPROG_CLAVE
               AND IFNULL(P_CAMPUS,TCAPR_TCAMP_CLAVE)=TCAPR_TCAMP_CLAVE
               AND IFNULL(P_NIVEL,TPROG_TNIVE_CLAVE)=TPROG_TNIVE_CLAVE; 
      END IF;
  
  END;    
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_PROGRAMA_TCEEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_PROGRAMA_TCEEL`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_PROGRAMA_TCEEL`(IN P_MATRICULA VARCHAR(10), IN P_PROGRAMA VARCHAR(10))
BEGIN

	/*
    EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
    PROCEDIMIENTO: CREADO PARA RETORNAR EN LA FORMA TCEEL LOS DATOS DEL ALUMNO.
    CREADO: MDE
    FECHA: 05/10/2022
    VERSIÓN 1.0
    PROYECTO: DESARROLLO SAES
   */
   
	 /*tprog_fecha_rvoe fechaExpedicion, */
   
		select tcamp_incorp IdCampus, tcamp_clave, tcamp_desc, 
			tprog_incorporante idCarrera, tprog_desc, tprog_rvoe numero, date_format(tprog_fecha_rvoe, '%d/%m/%Y') fechaExpedicion, 
			tprog_periodicidad idTipoPeriodo,
			case when  tprog_periodicidad='91' then 'SEMESTRE'
				 when  tprog_periodicidad='92' then 'BIMESTRE'
				 when  tprog_periodicidad='93' then 'BIMESTRE'
				 when  tprog_periodicidad='94' then 'TETRAMESTRE'
				 when  tprog_periodicidad='260' then 'TRIMESTRE'
				 when  tprog_periodicidad='261' then 'MODULAR'
			end tprog_periodicidad,
			tprog_clave_plan clavePlan, tnive_incorp idNivelEstudios, tnive_desc, tprog_creditos totalCreditos,
			tprog_cal_minima calificacionMinima , tprog_cal_maxima calificacionMaxima, 
			tprog_min_aprob calificacionMinimaAprobatoria
		from tprog, testu s, tnive, tcamp 
			where tprog_clave=P_PROGRAMA -- 'ADP032016M'
			and	testu_tpers_num in (select tpers_num from tpers where tpers_id= P_MATRICULA) -- 'U99203594')
			and	testu_tprog_clave=tprog_clave
			and	testu_tpees_clave in (select max(testu_tpees_clave) 
									  from testu ss
									  where s.testu_tpers_num=ss.testu_tpers_num 
                                      and testu_tprog_clave=ss.testu_tprog_clave)
			and  testu_tcamp_clave=tcamp_clave
			and  tprog_tnive_clave=tnive_clave;
   END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_PROMEDIO_TCEEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_PROMEDIO_TCEEL`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_PROMEDIO_TCEEL`(IN P_MATRICULA VARCHAR(10), IN P_PROGRAMA VARCHAR(10))
BEGIN

	/*
    EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
    PROCEDIMIENTO: CREADO PARA RETORNAR EN TCEEL EL PROMEDIO DEL ALUMNO .
    CREADO: MDE
    FECHA: 05/10/2022
    VERSIÓN 1.0
    PROYECTO: DESARROLLO SAES
   */
   
	   
-- Promedio
		select round(avg(tcali_puntos),1) 
        promedio from tkard, tcali, tprog
		where tkard_tpers_num in (select tpers_num 
								 from tpers 
                                 where tpers_id= P_MATRICULA) -- 'U99203594')
		and   tkard_tprog_Clave= P_PROGRAMA -- 'ADP032016M'
		and   tkard_tprog_clave=tprog_clave and tkard_tprog_clave=tprog_clave
		and   tprog_tnive_clave=tcali_tnive_clave and tkard_tcali_clave=tcali_clave
		and   tcali_ind_aprob='S' ;

   END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for p_obten_tbapa
-- ----------------------------
DROP PROCEDURE IF EXISTS `p_obten_tbapa`;
delimiter ;;
CREATE PROCEDURE `p_obten_tbapa`(IN p_term     VARCHAR(6),
                               IN p_campus   VARCHAR(3),
                               IN p_nivel    VARCHAR(6))
begin
    /*
      Empresa: COREMO Soluciones TecnologÃ­cas
      Creado: JJCM
      Fecha: 15/08/2022
      Versión 1.0
      Proyecto: Desarrollo SAES
    
      Errores variables 0 S/E
      Errores variables 1 C/E
    */
    DECLARE l_porcentaje       INT;
    DECLARE l_fecha_ini        DATE;
    DECLARE l_fecha_fin        DATE;
    DECLARE l_contar           INT;
    DECLARE l_code_error       INT;
    DECLARE l_error            VARCHAR(100);
    
  BEGIN
    -- Valida valores de periodo
    IF p_term IS NULL THEN
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'El periodo viene como valor nulo';    
    END IF;
    
    SELECT count(*)
    INTO l_contar
    FROM tpees
    WHERE 1 = 1
    AND tpees_fin >= curdate() and tpees_estatus='A'
    AND tpees_clave = p_term; 
    
    IF l_contar = 0  THEN
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'El periodo no se encuentra en el catalogo';  
    END IF;
  
  -- Valida Campus
    SET l_contar=0;
    
    /*
    IF p_campus IS NULL THEN
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'El campus viene como valor nulo';   
    END IF;
  
    SELECT COUNT(*)
    INTO l_contar
    FROM tcamp
    WHERE 1 = 1
    AND tcamp_clave = p_campus;
    
    IF l_contar = 0  then
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'El campus no se encuentra en el catalogo';  
    END IF;
    
    -- Validamos Nivel
    SET l_contar=0;
    
    /*
    IF p_nivel IS NULL THEN
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'El nivel viene como valor nulo';  
    END IF;
    
    SELECT COUNT(*)
    INTO l_contar
    FROM tcapr, 
         tprog, 
         tnive
    WHERE 1 = 1
    AND tcapr_tcamp_clave=p_campus
    AND tcapr_tprog_clave=tprog_clave
    AND tprog_tnive_clave=tnive_clave
    AND tnive_clave = p_nivel;    
    
    IF l_contar = 0 THEN
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'El nivel no se encuentra en el catalogo';  
    END IF;
    
    -- Validamos que exista en la tabla de descuentos TBAPA
    SET l_contar = 0;
    
    SELECT count(*)
    INTO l_contar
    FROM tbapa
    WHERE 1 = 1
    AND tbapa_tpees_clave = p_term
    AND tbapa_tcamp_clave = p_campus
    AND tbapa_tnive_clave = p_nivel;
    
   -- IF l_contar = 0 THEN
    --  SIGNAL SQLSTATE '45000'
    --  SET MESSAGE_TEXT = 'Esta combinación no encontro registros';  
   -- ELSE*/
      
      SELECT tbapa_porcen porcentaje,
             tbapa_fecha_ini fecha_ini,
             tbapa_fecha_fin fecha_fin
      FROM tbapa
      WHERE 1 = 1
      AND tbapa_tpees_clave = p_term
      AND IFNULL(p_campus,tbapa_tcamp_clave)=tbapa_tcamp_clave
      AND IFNULL(p_nivel,tbapa_tnive_clave) = tbapa_tnive_clave;
      
   -- END IF;
    
  END;

end
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_OBTEN_TOT_MATERIAS_TCEEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTEN_TOT_MATERIAS_TCEEL`;
delimiter ;;
CREATE PROCEDURE `P_OBTEN_TOT_MATERIAS_TCEEL`(IN P_MATRICULA VARCHAR(10), IN P_PROGRAMA VARCHAR(10))
BEGIN

	/*
    EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
    PROCEDIMIENTO: CREADO PARA RETORNAR EN TCEEL EL TOTAL DE MATERIAS EN KARDEX DEL ALUMNO .
    CREADO: MDE
    FECHA: 05/10/2022
    VERSIÓN 1.0
    PROYECTO: DESARROLLO SAES
   */
   
	   
-- Total materias
	select count(*) Asignaturas_total 
    from tkard, tcali, tprog
	where tkard_tpers_num in (select tpers_num 
							  from tpers 
                              where tpers_id=P_MATRICULA) -- 'U99203594')
	and tkard_tprog_Clave=P_PROGRAMA -- 'ADP032016M'
	and tkard_tprog_clave=tprog_clave and tkard_tprog_clave=tprog_clave
	and tprog_tnive_clave=tcali_tnive_clave and tkard_tcali_clave=tcali_clave
	and tcali_ind_aprob='S';

   END
;;
delimiter ;

