-- ----------------------------
-- Procedure structure for P_OBTIENE_FOLIO_TCEEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_OBTIENE_FOLIO_TCEEL`;
delimiter ;;
CREATE PROCEDURE `P_OBTIENE_FOLIO_TCEEL`(IN P_MATRICULA VARCHAR(10), IN P_PROGRAMA VARCHAR(10))
BEGIN

	/*
    EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
    PROCEDIMIENTO: CREADO PARA RETORNAR EN TCEEL EL NUMERO DE FOLIO DEL CERTIFICADO ELECTRÓNICO.
    CREADO: MDE
    FECHA: 05/10/2022
    VERSIÓN 1.0
    PROYECTO: DESARROLLO SAES
   */
   
	    declare vl_camp_clave varchar(3);
	
     select testu_tcamp_clave
     into vl_camp_clave
     from testu s
     where testu_tpers_num in (select tpers_num 
								  from tpers 
                                  where tpers_id= P_MATRICULA) -- P_MATRICULA) -- 'U99203594')
		and testu_tprog_clave= P_PROGRAMA -- P_PROGRAMA -- 'ADP032016M'
		and testu_tpees_clave in (select max(testu_tpees_clave) 
								  from testu ss
								  where s.testu_tpers_num=ss.testu_tpers_num 
                                  and s.testu_tprog_clave=ss.testu_tprog_clave);
                                  
		update tcseq set tcseq_numero = tcseq_numero+1
        where 
        tcseq_tcamp_clave = vl_camp_clave
        and tcseq_tseqn_clave = '009';		
     

	   -- Obtiene número de folio
		select lpad(tcseq_numero,tcseq_longitud,'0') folio, testu_tcamp_clave
		from tcseq, testu s
		where testu_tpers_num in (select tpers_num 
								  from tpers 
                                  where tpers_id= P_MATRICULA) -- 'U99203594')
		and testu_tprog_clave= P_PROGRAMA -- 'ADP032016M'
		and testu_tpees_clave in (select max(testu_tpees_clave) 
								  from testu ss
								  where s.testu_tpers_num=ss.testu_tpers_num 
                                  and s.testu_tprog_clave=ss.testu_tprog_clave)
								  and testu_tcamp_clave=tcseq_tcamp_clave 
                                  and tcseq_tseqn_clave='009';

   END
;;
delimiter ;

