-- ----------------------------
-- Procedure structure for P_TIPO_CERT_TCEEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_TIPO_CERT_TCEEL`;
delimiter ;;
CREATE PROCEDURE `P_TIPO_CERT_TCEEL`(IN P_MATRICULA VARCHAR(10), IN P_PROGRAMA VARCHAR(10))
BEGIN

	/*
    EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
    PROCEDIMIENTO: CREADO PARA RETORNAR EN TCEEL EL ID DEL TIPO DE CERTIFICACIÓN .
    CREADO: MDE
    FECHA: 05/10/2022
    VERSIÓN 1.0
    PROYECTO: DESARROLLO SAES
   */
   
   
	-- Tipo Certificado
		select case when x.cursos >= x.tprog_cursos then 
        'TOTAL' else 'PARCIAL' 
        end  IdTipoCertificacion
		from (
		select tprog_cursos,
		(select count(*) 
        from tkard, tcali, tprog
		where tkard_tpers_num in (select tpers_num 
								  from tpers 
                                  where tpers_id=P_MATRICULA) -- 'U99203594')
		 and tkard_tprog_clave=tprog_clave and tkard_tprog_clave=tprog_clave
		 and tprog_tnive_clave=tcali_tnive_clave and tkard_tcali_clave=tcali_clave
		 and tcali_ind_aprob='S')cursos
		from tprog
		where tprog_clave= P_PROGRAMA) x;-- 'ADP032016M') x;

   END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_TITULACION_NIVE
