DROP PROCEDURE IF EXISTS `P_TITULACION_NIVE`;
delimiter ;;
CREATE PROCEDURE `P_TITULACION_NIVE`(IN `P_OPTITU` VARCHAR(3))
BEGIN
    /*
      EMPRESA: COREMO SOLUCIONES TECNOLOGíCAS
      CREADO: JRO
      FECHA: 18/09/2022
      VERSIóN 1.0
      PROYECTO: DESARROLLO SAES
    
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
    */
    
    DECLARE L_ERROR            VARCHAR(100);
    DECLARE L_CONTAR           INT;
    DECLARE VL_RESPUESTA       VARCHAR(300);
    
    BEGIN
      SELECT COUNT(*)
        INTO L_CONTAR
        FROM TTINI
       WHERE     TTINI_TTIOP_CLAVE = P_OPTITU; 
    
    
      IF L_CONTAR = 0  THEN
        
        SET VL_RESPUESTA = CONCAT('NO SE ENCUENTRA INFORMACION PARA LA OPCION ',P_OPTITU);
        
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = VL_RESPUESTA;
        
      ELSE
        SELECT TTINI_TNIVE_CLAVE NIVEL,
               TTINI_CREDITOS CREDITOS,
               TTINI_PROMEDIO PROMEDIO,
               TTINI_TCOCO_CLAVE CODIGO
          FROM TTINI
         WHERE TTINI_TTIOP_CLAVE = P_OPTITU;
      END IF;
  
  END;    
END
;;
