-- ----------------------------
-- Procedure structure for p_update_tbapa
-- ----------------------------
DROP PROCEDURE IF EXISTS `p_update_tbapa`;
delimiter ;;
CREATE PROCEDURE `p_update_tbapa`(IN p_periodo    varchar(6),
                                  IN p_campus     varchar(3),
                                  IN p_nivel      varchar(2),
                                  IN p_porcentaje decimal(6,1),
                                  IN p_fecha_ini  date,
                                  IN p_fecha_fin  date,
                                  IN p_porc_anterior decimal(6,1),
                                  IN p_fi         date,
                                  IN p_ff         date,
                                  in p_user       VARCHAR(50))
begin
    DECLARE l_contar int;
    declare l_retorna varchar(200);
    SET l_retorna ='EXITO';
    
  begin
  
    if p_fecha_ini = p_fecha_fin then
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'Las fechas no pueden ser las mismas'; 
    
    end if;
    
    IF p_fecha_ini > p_fecha_fin THEN
      
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'La fecha de inicio no puede ser mayor a la fecha fin';    
    
    END IF;
    
    -- Trasalape
    select count(*)
    into l_contar
    from TBAPA
    where 1 = 1
    and TBAPA_TPEES_CLAVE = p_periodo
    and TBAPA_TCAMP_CLAVE = p_campus
    and TBAPA_TNIVE_CLAVE = p_nivel
    and ((p_fecha_ini between TBAPA_FECHA_INI and TBAPA_FECHA_FIN or p_fecha_fin between TBAPA_FECHA_INI and TBAPA_FECHA_FIN)
	        or (p_fecha_ini <= TBAPA_FECHA_INI and p_fecha_fin >= TBAPA_FECHA_FIN)
	        or (p_fecha_ini >= TBAPA_FECHA_INI and p_fecha_fin <= TBAPA_FECHA_FIN)
	      )
    and(tbapa_fecha_ini <> p_fi and tbapa_fecha_fin <> p_ff) ;   
    
    if l_contar > 0 then
      
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'No se puede tener la misma configuración entre varios rangos de fechas';    
      
    end if;
    
    
    update TBAPA set TBAPA_PORCEN      = p_porcentaje,
                     TBAPA_FECHA_INI   = STR_TO_DATE(p_fecha_ini, 'd%m%y'),
                     TBAPA_FECHA_FIN   = STR_TO_DATE(p_fecha_fin,'d%m%y'),
                     TBAPA_DATE = now()
      where 1 = 1
      and TBAPA_TPEES_CLAVE =p_periodo
      and TBAPA_TCAMP_CLAVE = p_campus
      and TBAPA_TNIVE_CLAVE = p_nivel
      and TBAPA_FECHA_INI = STR_TODATE(p_fi, 'd%m%y')
      and TBAPA_FECHA_FIN = p_ff(p_ff, 'd%m%y')
      and TBAPA_PORCEN = p_porc_anterior;  
        
  end;
    
  commit;       
  
  if l_retorna <>'EXITO' then
  
    signal sqlstate'45000' set message_text='Error al actualizar';
    
  end if;
  
  select l_retorna;

end
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_VALIDA_BITACORA_KARDEX
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_VALIDA_BITACORA_KARDEX`;
delimiter ;;
CREATE PROCEDURE `P_VALIDA_BITACORA_KARDEX`(IN P_TPERS_NUM INT,
                                                 IN P_TPROG_CLAVE VARCHAR(10),
                                                 IN P_TPEES_CLAVE VARCHAR(6),
                                                 IN P_TMATE_CLAVE VARCHAR(10))
BEGIN

    /*

      EMPRESA: COREMO SOLUCIONES TECNOLOGÍCAS.
      PROCEDIMIENTO: VALIDA QUE EXISTA BITACORA EN EL KARDEX DEL ALUMNO


      CREADO: JCM
      FECHA: 27/09/2022
      VERSIÓN 1.0
      PROYECTO: DESARROLLO SAES
      
    */
    
    DECLARE VL_RESPUESTA  VARCHAR(100);
    DECLARE L_TCAMP_CLAVE VARCHAR(2);
    DECLARE L_CONTAR      INT;

    
    IF P_TPERS_NUM IS NULL OR P_TPERS_NUM ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBES DE SELECIONAR UN ALUMNO PARA CONSULTAR');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    IF P_TPROG_CLAVE IS NULL OR P_TPROG_CLAVE ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBES DE SELECIONAR UN PROGRAMA PARA CONSULTAR');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    
    IF P_TMATE_CLAVE IS NULL OR P_TMATE_CLAVE ='' THEN
    
      SET VL_RESPUESTA = CONCAT('DEBES DE SELECIONAR UNA MATERIA PARA CONSULTAR');
    
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = VL_RESPUESTA;
    
    END IF;
    
    
       
    

        SELECT DISTINCT TESTU_TCAMP_CLAVE
        INTO L_TCAMP_CLAVE
        FROM TESTU A
        WHERE 1 = 1
        AND A.TESTU_TPERS_NUM = P_TPERS_NUM
        AND A.TESTU_TPROG_CLAVE = P_TPROG_CLAVE
        AND A.TESTU_TPEES_CLAVE = (SELECT MAX(B.TESTU_TPEES_CLAVE)
                                   FROM TESTU B
                                   WHERE 1 = 1
                                   AND A.TESTU_TPERS_NUM = B.TESTU_TPERS_NUM
                                   AND A.TESTU_TPROG_CLAVE = B.TESTU_TPROG_CLAVE);
      
    
        SELECT count(*)
        into L_CONTAR
        FROM TKARA a 
        WHERE 1 = 1
        AND TKARA_TPERS_NUM   = P_TPERS_NUM
        AND TKARA_TPEES_CLAVE = P_TPEES_CLAVE 
        AND TKARA_TCAMP_CLAVE = L_TCAMP_CLAVE
        AND TKARA_TPROG_CLAVE = P_TPROG_CLAVE
        AND TKARA_TMATE_CLAVE = P_TMATE_CLAVE;
        
        IF L_CONTAR > 0 THEN
        
          SELECT 1 VALIDA_DATO;
        
        ELSE
        
          SELECT 0 VALIDA_DATO;
        
        END IF;
  
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_VALIDA_FECHA
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_VALIDA_FECHA`;
delimiter ;;
CREATE PROCEDURE `P_VALIDA_FECHA`(IN P_PERIODO  VARCHAR(7),
                                       IN P_CAMPUS   VARCHAR(3),
                                       IN P_MATERIA  VARCHAR(10),
                                       IN P_GRUPO    VARCHAR(6),
                                       IN P_FECHA    VARCHAR(10))
BEGIN

 DECLARE VL_DIAS      INT;
 DECLARE vl_entra     INT;                                    

    /*
      EMPRESA: COREMO SOLUCIONES TECNOLOGíCAS
      CREADO: JRO
      FECHA: 01/09/2022
      VERSIóN 1.0
      PROYECTO: DESARROLLO SAES
    
      ERRORES VARIABLES 0 S/E
      ERRORES VARIABLES 1 C/E
    */
    IF ((((  P_PERIODO IS NULL OR P_CAMPUS IS NULL)
          OR P_MATERIA IS NULL)
             OR P_GRUPO IS NULL)
                OR P_FECHA    IS NULL) THEN
                
       SIGNAL SQLSTATE '45000'
          SET MESSAGE_TEXT = 'FAVOR DE VALIDAR LOS CAMPUS VACIOS';    
                
    ELSE
       BEGIN
         SELECT TIMESTAMPDIFF(day,date(STR_TO_DATE(P_FECHA,'%d/%m/%Y')),date(sysdate()))
           INTO VL_DIAS
         FROM DUAL;   
       END;
   
       IF VL_DIAS > 3 THEN 
         SIGNAL SQLSTATE '45000'
            SET MESSAGE_TEXT = 'RANGO DE FECHA MAXIMO 3 DIAS';    
       ELSE
         BEGIN
          SELECT COUNT(*)

            INTO VL_ENTRA
            FROM THORA
           WHERE     THORA_TPEES_CLAVE = P_PERIODO
                 AND THORA_TCAMP_CLAVE = P_CAMPUS
                 AND THORA_TMATE_CLAVE = P_MATERIA
                 AND THORA_TGRUP_CLAVE = P_GRUPO
                 and (case 
                      when THORA_TDIAS_CLAVE = 1 then 'SUN' 
                      when THORA_TDIAS_CLAVE = 2 then 'MON' 
                      when THORA_TDIAS_CLAVE = 3 then 'TUE' 
                      when THORA_TDIAS_CLAVE = 4 then 'WED' 
                      when THORA_TDIAS_CLAVE = 5 then 'THU' 
                      when THORA_TDIAS_CLAVE = 6 then 'FRI' 
                      when THORA_TDIAS_CLAVE = 7 then 'SAT' 
                          end) = DATE_FORMAT(DATE(STR_TO_DATE(P_FECHA,'%d/%m/%Y')),'%a');
            
           END;
        
           IF VL_ENTRA = 0 THEN
             SIGNAL SQLSTATE '45000'
                SET MESSAGE_TEXT = 'NO CUENTA CON HORARIO EN ESTA FECHA';    
           ELSE
              SELECT 'EXITO' RESPUESTA
              FROM DUAL;
           END IF;
       END IF;
    END IF;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for P_VALIDA_FOLIO_TCEEL
-- ----------------------------
DROP PROCEDURE IF EXISTS `P_VALIDA_FOLIO_TCEEL`;
delimiter ;;
CREATE PROCEDURE `P_VALIDA_FOLIO_TCEEL`(IN P_MATRICULA VARCHAR(10), IN P_PROGRAMA VARCHAR(10))
BEGIN

	/*
