delimiter ;

-- ----------------------------
-- Procedure structure for Valida_Usuario
-- ----------------------------
DROP PROCEDURE IF EXISTS `Valida_Usuario`;
delimiter ;;
CREATE PROCEDURE `Valida_Usuario`(IN P_USUARIO VARCHAR(10), IN P_PASS VARCHAR (100))
BEGIN
DECLARE vmValida INT;
DECLARE vmNombre VARCHAR(80);
	SELECT val_usuario(P_USUARIO,P_PASS) INTO vmValida;   
    IF vmValida=1 THEN
		SELECT vmValida P_VALIDA, tuser_desc , b.trole_desc
		FROM tuser a, trole b
		WHERE trole_clave=tuser_trole_clave AND
        a.TUSER_CLAVE=UPPER(P_USUARIO); 
    ELSE	
		SELECT vmValida P_VALIDA, '' tuser_desc, '' trole_desc;
	END IF;
    
END
;;
delimiter ;

-- ----------------------------
-- Function structure for val_pregunta
-- ----------------------------
DROP FUNCTION IF EXISTS `val_pregunta`;
delimiter ;;
CREATE FUNCTION `val_pregunta`(P_USUARIO VARCHAR(10), P_CVE_PREG INT, P_RESPUESTA_PREG VARCHAR(100))
 RETURNS int
BEGIN
DECLARE vmExiste INT;
	SELECT COUNT(*)
    INTO vmExiste
	FROM tprse a, tuser b
	WHERE b.tuser_clave=a.tprse_tuser_clave AND
	b.tuser_clave=P_USUARIO AND
	a.tprse_tpreg_clave=P_CVE_PREG AND
	a.tprse_respuesta=P_RESPUESTA_PREG
	;
RETURN vmExiste; 
END
;;
delimiter ;

-- ----------------------------
-- Function structure for val_usuario
-- ----------------------------
DROP FUNCTION IF EXISTS `val_usuario`;
delimiter ;;
CREATE FUNCTION `val_usuario`(P_USUARIO VARCHAR(10), P_PASS VARCHAR (100))
 RETURNS int
BEGIN
DECLARE vmTienePass INT;
DECLARE vmValida INT;
	SELECT COUNT(tuser_desc) 
    INTO vmTienePass
    FROM tuser WHERE UPPER(TUSER_CLAVE)=UPPER(P_USUARIO);
    
    IF vmTienePass>0 THEN
		SELECT COUNT(tuser_pass) INTO vmTienePass
		FROM tuser WHERE UPPER(TUSER_CLAVE)=UPPER(P_USUARIO);
		IF vmTienePass>0 THEN
			SELECT COUNT(tuser_pass) 
			INTO vmTienePass
			FROM tuser 
			WHERE UPPER(TUSER_CLAVE)=UPPER(P_USUARIO) AND
			cast(AES_DECRYPT(tuser_pass,tuser_clave) as char)=CONVERT(P_PASS,CHAR);
      
			IF vmTienePass>0 THEN
				SET vmValida=1;
			ELSE
				SET vmValida:=2;
			END IF;	
		ELSE
			SET vmValida=3;
        END IF;
	ELSE
		SET vmValida:=0;
    END IF;
RETURN vmValida;   
END
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;
